-- Schema for Domain: inventory | Business: Chemical Mfg | Version: v1_mvm
-- Generated on: 2026-05-06 14:37:10

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `chemical_mfg_ecm`.`inventory` COMMENT 'Manages real-time stock positions for raw materials, intermediates, finished goods, and packaging materials across all warehouse locations and tank farms. Governs FIFO/FEFO lot rotation, hazardous material storage compliance, lot numbers, expiration dates, inventory movements, stock transfers, inventory valuation, and quarantine status. Integrates with SAP EWM and WMS for warehouse operations.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`stock_position` (
    `stock_position_id` BIGINT COMMENT 'Primary key for stock_position',
    `inventory_target_id` BIGINT COMMENT 'Unique surrogate identifier for each stock position record representing a material at a specific storage location, bin, or tank farm. Primary key for the stock_position data product.',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Needed for daily inventory balance reports linking each stock position to its master chemical product, enabling accurate valuation, SDS lookup, and REACH compliance.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Required for cost accounting reports that allocate inventory value to cost centers per plant, enabling accurate product cost roll‑up.',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to maintenance.equipment. Business justification: Spare parts allocation for equipment repairs; maintenance work orders consume inventory items per equipment, required for parts consumption reporting.',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: Stock positions in chemical plants are physically located within process unit functional locations (e.g., reactor area, tank farm). This link supports PSM inventory-by-process-unit reporting, maintena',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: stock_position tracks a real-time stock position for a specific lot/batch. The lot_number STRING column is denormalized; adding lot_id FK to inventory.lot normalizes this and enables FIFO/FEFO lot rot',
    `mrp_run_id` BIGINT COMMENT 'Foreign key linking to planning.mrp_run. Business justification: MRP runs consume stock position data (on-hand, reserved, in-transit quantities) as primary inputs to net requirements calculation. Chemical manufacturing planners must trace which MRP run last process',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record identifying the specific raw material, intermediate, finished good, or packaging material held in this stock position. Sourced from SAP MM material master.',
    `production_plant_id` BIGINT COMMENT 'Reference to the manufacturing plant or facility where this stock position is held. Aligns with SAP organizational structure for plant-level inventory management.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Segment profitability reporting (CO-PA): inventory positions are assigned to profit centers for business segment reporting and profitability analysis. Standard SAP controlling requirement in chemical ',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to supply.purchase_order. Business justification: Required for traceability of on‑hand stock to the originating purchase order for regulatory recall and inventory valuation reports.',
    `quality_specification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_specification. Business justification: Stock positions in chemical manufacturing are managed by quality specification (grade, purity class). This FK enables grade-segregated inventory reporting, ensures correct spec is applied during stock',
    `sds_record_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.sds_record. Business justification: OSHA HazCom and GHS require SDS to be accessible at the point of storage for every hazardous chemical. Linking stock_position directly to sds_record enables warehouse safety compliance checks, storage',
    `standard_cost_id` BIGINT COMMENT 'Foreign key linking to finance.standard_cost. Business justification: Balance sheet inventory valuation: stock_position carries valuation_price and valuation_class used to compute inventory value. Linking to standard_cost enables automated standard cost roll-up, price v',
    `storage_bin_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_bin. Business justification: stock_position has a storage_bin STRING column representing the bin code. storage_bin is the master record for individual bins within a warehouse location. Adding storage_bin_id FK normalizes the bin ',
    `warehouse_location_id` BIGINT COMMENT 'Reference to the specific warehouse storage location, bin, or tank farm where the material is physically stored. Managed within SAP EWM warehouse structure.',
    `available_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material available for unrestricted use, calculated as on-hand quantity minus reserved, blocked, and quality inspection quantities. Drives ATP (Available-to-Promise) checks in SAP SD and production planning in SAP PP.',
    `blocked_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material placed in blocked stock status due to quality failures, regulatory holds, damage, or quarantine. Blocked stock is not available for production or shipment until released by QA or EHS.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this stock position record was first created in the source system (SAP EWM). Provides audit trail for record lineage and supports SOX compliance for inventory record integrity.',
    `expiration_date` DATE COMMENT 'The date on which the material lot expires and is no longer suitable for use. Critical for FEFO (First Expired First Out) lot rotation logic, regulatory compliance, and preventing use of out-of-specification materials. Sourced from SAP batch classification.',
    `goods_receipt_date` DATE COMMENT 'The date on which the material was received into the warehouse via a goods receipt posting in SAP MM. Used as the FIFO reference date for lot rotation when manufacture date is unavailable.',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether the material in this stock position is classified as a hazardous material requiring special storage, handling, and reporting under OSHA, DOT, EPA, and REACH regulations. Triggers hazmat storage compliance checks in EHS management.',
    `in_transit_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material currently in transit between storage locations, plants, or external suppliers. Represents stock that has been shipped but not yet received at the destination, tracked via SAP EWM transfer orders.',
    `last_count_date` DATE COMMENT 'The date on which the most recent physical inventory count or cycle count was performed for this stock position. Used to assess inventory accuracy and schedule next count per SOX and ISO 9001 audit requirements.',
    `last_movement_date` DATE COMMENT 'The date of the most recent inventory movement (goods issue, goods receipt, transfer order, or stock transfer) affecting this stock position. Used to identify slow-moving or obsolete inventory for write-off analysis.',
    `lot_rotation_method` STRING COMMENT 'The inventory rotation strategy applied to this stock position for picking and consumption sequencing. FIFO (First In First Out) is used for most materials; FEFO (First Expired First Out) is mandatory for materials with expiration dates per GMP requirements.. Valid values are `FIFO|FEFO|LIFO|LEFO`',
    `manufacture_date` DATE COMMENT 'The date on which the material lot was manufactured or produced. Used in conjunction with expiration_date to calculate shelf life and support FIFO/FEFO rotation. Sourced from SAP batch master or COA.',
    `maximum_stock_quantity` DECIMAL(18,2) COMMENT 'The maximum allowable stock quantity for this material at this storage location, constrained by tank capacity, regulatory storage limits, or warehouse space. Enforced by SAP EWM capacity checks and EHS hazmat storage quantity limits under OSHA PSM.',
    `on_hand_quantity` DECIMAL(18,2) COMMENT 'Total physical quantity of the material currently present at the storage location, including all stock types (unrestricted, quality inspection, blocked). Represents the gross inventory position before any reservations or holds are applied.',
    `quality_inspection_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material currently under quality inspection in the LIMS or SAP QM module. This stock is not available for use until the inspection lot is closed and the material is released to unrestricted stock.',
    `quarantine_reason` STRING COMMENT 'Free-text description of the reason this stock position has been placed in quarantine or blocked status. Examples include failed QC test, regulatory hold, contamination suspicion, or pending CAPA investigation. Populated when stock_status is quarantine or stock_type is blocked.',
    `reorder_point` DECIMAL(18,2) COMMENT 'The minimum stock level at which a replenishment order should be triggered for this material at this storage location. Used by SAP MRP (Material Requirements Planning) to generate purchase requisitions or production orders automatically.',
    `reserved_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material reserved against open production orders, sales orders, or transfer orders in SAP. Reserved stock is committed but not yet physically moved, reducing the available quantity for new demand.',
    `safety_stock_quantity` DECIMAL(18,2) COMMENT 'The minimum buffer stock quantity maintained to protect against supply disruptions, demand variability, or lead time uncertainty. Defined in SAP MRP parameters and used in available quantity calculations for production planning.',
    `snapshot_timestamp` TIMESTAMP COMMENT 'The date and time at which this stock position record was captured or last refreshed from the source system (SAP EWM/S4HANA). Represents the as-of time for the inventory snapshot, critical for real-time inventory reporting and reconciliation.',
    `special_stock_indicator` STRING COMMENT 'Indicates whether this stock position represents a special stock type such as consignment inventory, project stock, sales-order-specific stock, or vendor-managed inventory (VMI). Drives distinct accounting and ownership rules in SAP MM.. Valid values are `none|consignment|project|sales_order|vendor_managed`',
    `stock_category` STRING COMMENT 'Classification of the material type held in this stock position. Drives inventory valuation rules, storage compliance requirements, and reporting segmentation across raw materials, intermediates, finished goods, and packaging materials.. Valid values are `raw_material|intermediate|finished_good|packaging|spare_part`',
    `stock_status` STRING COMMENT 'Current lifecycle status of the stock position record. Quarantine status is applied when material is pending investigation or regulatory hold. Expired indicates the material has passed its expiration date. Recalled indicates a product recall event has been triggered.. Valid values are `active|quarantine|expired|disposed|recalled`',
    `stock_type` STRING COMMENT 'SAP stock type classification indicating the usability state of the inventory. Unrestricted stock is available for use; quality_inspection stock is pending QC release; blocked stock is not available for use; returns stock is from customer returns; in_transit stock is between locations.. Valid values are `unrestricted|quality_inspection|blocked|returns|in_transit`',
    `storage_type` STRING COMMENT 'Classification of the physical storage infrastructure type where the material is held. Drives hazardous material storage compliance rules under OSHA PSM, NFPA, and DOT regulations. [ENUM-REF-CANDIDATE: bulk_tank|drum_rack|pallet_rack|cold_storage|hazmat_cage|silo|ibc_bay — promote to reference product]',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which all quantity fields for this stock position are expressed. Chemical manufacturing uses weight (KG, MT), volume (L, GAL, M3), and count (EA, DRUM, IBC) units depending on material type. Aligns with SAP MM base UOM. [ENUM-REF-CANDIDATE: KG|LB|L|GAL|MT|TON|EA|BAG|DRUM|IBC|M3|FT3 — 12 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this stock position record was last modified in the source system. Used for change data capture (CDC) processing in the Databricks Silver Layer pipeline and audit trail maintenance.',
    `valuation_class` STRING COMMENT 'SAP valuation class code that determines the general ledger (GL) accounts to which inventory postings are made for this material. Links inventory movements to the correct COGS and balance sheet accounts per FASB and SOX requirements.. Valid values are `^[A-Z0-9]{4,10}$`',
    `valuation_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the valuation_price is expressed (e.g., USD, EUR). Required for multi-currency inventory valuation reporting across global plant locations.. Valid values are `^[A-Z]{3}$`',
    `valuation_price` DECIMAL(18,2) COMMENT 'Reference unit price used to calculate the inventory valuation of this stock position, expressed in the valuation currency. Carried as a reference attribute for inventory reporting; authoritative valuation is owned by the Finance domain (SAP FI/CO). May reflect standard cost or moving average price per SAP valuation class.',
    `warehouse_number` STRING COMMENT 'The SAP EWM warehouse number identifying the physical warehouse complex managing this stock position. Used for multi-warehouse inventory segregation and reporting.. Valid values are `^[A-Z0-9]{1,10}$`',
    CONSTRAINT pk_stock_position PRIMARY KEY(`stock_position_id`)
) COMMENT 'Real-time stock position master record for each material (raw material, intermediate, finished good, packaging) at each storage location, bin, or tank farm. Tracks on-hand quantity, available quantity, reserved quantity, blocked quantity, unit of measure, batch/lot number, stock category, and stock type (unrestricted, quality inspection, blocked, returns). Serves as the primary SSOT for current inventory levels across all SAP EWM-managed warehouses and tank farms. Supports FIFO/FEFO lot rotation logic and hazardous material storage compliance. Valuation carried as reference attribute for inventory reporting; authoritative valuation owned by finance domain.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`warehouse_location` (
    `warehouse_location_id` BIGINT COMMENT 'Primary key for warehouse_location',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Warehouse overhead cost allocation: warehouse locations are assigned to cost centers for storage cost allocation (utilities, labor, depreciation). Chemical manufacturing finance teams require warehous',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: In SAP-based chemical plants, warehouse storage locations map directly to maintenance functional locations (FLOCs) for PSM compliance reporting, hazmat area inspection scheduling, and maintenance plan',
    `hazmat_storage_rule_id` BIGINT COMMENT 'Foreign key linking to inventory.hazmat_storage_rule. Business justification: warehouse_location has hazmat-related attributes (ghs_hazard_class_compatibility, fire_zone_code, ventilation_class, nfpa ratings) that should be governed by a hazmat_storage_rule. Adding hazmat_stora',
    `aisle` STRING COMMENT 'Alphanumeric identifier for the aisle within the warehouse where this storage location is physically situated. Used for warehouse navigation, pick path optimization, and physical inventory counting.. Valid values are `^[A-Z0-9]{1,10}$`',
    `area_sqm` DECIMAL(18,2) COMMENT 'Physical floor area of this storage location in square meters. Used for capacity planning, fire load calculations, and regulatory reporting of storage area dimensions per EPA and OSHA requirements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this warehouse location master record was first created in the system. Used for data lineage, audit trail, and record lifecycle management.',
    `electrical_area_classification` STRING COMMENT 'NEC/NFPA 70 electrical area classification for this storage location, indicating the presence and likelihood of flammable vapors or combustible dust. Determines requirements for explosion-proof electrical equipment. [ENUM-REF-CANDIDATE: unclassified|class_i_div1|class_i_div2|class_ii_div1|class_ii_div2|zone_0|zone_1|zone_2 — promote to reference product]',
    `epa_regulatory_citation` STRING COMMENT 'Applicable EPA regulatory citation(s) governing storage requirements at this location (e.g., 40 CFR Part 264 - Hazardous Waste Storage, 40 CFR Part 68 - RMP). Used for environmental compliance documentation, permit management, and regulatory audit support.',
    `fire_zone_code` STRING COMMENT 'Identifier for the fire protection zone in which this storage location resides. Fire zones define the boundaries of fire suppression systems (sprinkler zones, deluge systems), fire detection circuits, and emergency evacuation areas. Referenced in PSM and HAZOP documentation.. Valid values are `^[A-Z0-9]{1,20}$`',
    `floor_load_capacity_kg_m2` DECIMAL(18,2) COMMENT 'Maximum allowable floor load in kilograms per square meter for this storage location. Ensures structural integrity of the warehouse floor when storing heavy drums, IBCs, or bulk containers. Referenced in facility engineering and OSHA compliance inspections.',
    `ghs_hazard_class_compatibility` STRING COMMENT 'Pipe-delimited list of GHS hazard classes that are approved for storage at this location (e.g., Flammable Liquid|Oxidizer|Corrosive). Governs which chemical materials may be placed here based on GHS classification. Used to enforce chemical segregation rules and prevent incompatible co-storage.',
    `height_m` DECIMAL(18,2) COMMENT 'Clear storage height in meters for this location. Used to determine maximum pallet stack height, forklift clearance requirements, and sprinkler system design (in-rack vs. ceiling sprinklers per NFPA 13).',
    `incompatible_hazard_classes` STRING COMMENT 'Pipe-delimited list of GHS hazard classes that must NOT be co-stored at this location due to chemical incompatibility or regulatory segregation requirements (e.g., Oxidizer|Explosive). Enforces NFPA and OSHA chemical segregation rules to prevent dangerous reactions.',
    `is_hazmat_approved` BOOLEAN COMMENT 'Indicates whether this storage location is approved and certified for the storage of hazardous materials per OSHA, EPA, and DOT regulations. True = approved for hazmat storage; False = not approved. Drives putaway rule enforcement in SAP EWM.',
    `is_quarantine_zone` BOOLEAN COMMENT 'Indicates whether this storage location is designated as a quarantine zone for materials under quality hold, regulatory hold, or investigation. True = quarantine zone; False = standard storage. Materials in quarantine zones are blocked from use in production or shipment per GMP and ISO 9001 requirements.',
    `is_temperature_controlled` BOOLEAN COMMENT 'Indicates whether this storage location has active temperature control (refrigeration, heating, or climate control). True = temperature controlled; False = ambient storage. Drives material assignment rules for temperature-sensitive chemicals and cold chain compliance.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent physical inspection or safety audit conducted at this storage location. Used to track inspection frequency compliance per OSHA PSM, EPA RMP, and internal EHS management requirements. Triggers re-inspection workflows when overdue.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this warehouse location master record was most recently updated. Used for change tracking, data synchronization with SAP EWM, and audit trail compliance.',
    `location_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the storage location within the warehouse network. Corresponds to SAP EWM storage bin or storage section code used in warehouse operations, goods movements, and transfer orders.. Valid values are `^[A-Z0-9]{2,20}$`',
    `location_name` STRING COMMENT 'Human-readable descriptive name for the storage location (e.g., Tank Farm A - Bay 3, Hazmat Drum Storage Zone 2, Cold Storage Room 1). Used in operational reports, safety documentation, and warehouse management interfaces.',
    `location_status` STRING COMMENT 'Current operational lifecycle status of the storage location. quarantine indicates the location is reserved for materials under quality hold. blocked indicates the location is temporarily unavailable for putaway or picking. under_maintenance indicates the location is undergoing inspection or repair.. Valid values are `active|inactive|quarantine|blocked|under_maintenance`',
    `location_type` STRING COMMENT 'Classification of the physical storage location type within the warehouse network. Determines applicable storage rules, capacity constraints, and regulatory requirements. [ENUM-REF-CANDIDATE: bulk_tank|drum_storage|cold_storage|hazmat_zone|quarantine_bay|finished_goods|intermediate_storage|open_yard — promote to reference product]',
    `max_humidity_pct` DECIMAL(18,2) COMMENT 'Maximum allowable relative humidity percentage for this storage location. Prevents moisture-induced degradation, corrosion, or microbial growth in stored materials. Expressed as a percentage (0–100).',
    `max_quantity_kg` DECIMAL(18,2) COMMENT 'Maximum quantity in kilograms of hazardous material permitted in this storage zone per EPA, OSHA PSM, and NFPA regulations. Used to enforce Tier II reporting thresholds, RMP covered quantity limits, and NFPA maximum allowable quantities (MAQ) per control area.',
    `max_temperature_c` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature in degrees Celsius for this location. Prevents thermal degradation, spontaneous reaction, or ignition of stored chemicals. Enforced against material SDS storage condition requirements.',
    `max_volume_liters` DECIMAL(18,2) COMMENT 'Maximum volumetric capacity in liters for this storage location. Particularly relevant for bulk tank farms and liquid chemical storage areas. Used to enforce maximum quantity limits per EPA and OSHA regulations.',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum allowable weight in kilograms that this storage location can safely hold. Enforced during putaway to prevent structural overloading. Critical for rack integrity compliance and OSHA load rating requirements.',
    `min_humidity_pct` DECIMAL(18,2) COMMENT 'Minimum allowable relative humidity percentage for this storage location. Relevant for hygroscopic chemicals, moisture-sensitive materials, and packaging integrity. Expressed as a percentage (0–100).',
    `min_temperature_c` DECIMAL(18,2) COMMENT 'Minimum allowable storage temperature in degrees Celsius for this location. Enforces cold chain and temperature-sensitive chemical storage requirements. Materials requiring higher minimum temperatures must not be stored here.',
    `next_inspection_due_date` DATE COMMENT 'Scheduled date by which the next physical inspection or safety audit of this storage location must be completed. Drives EHS compliance calendar and corrective action workflows in Intelex EHS Management.',
    `nfpa_fire_diamond_flammability` STRING COMMENT 'NFPA 704 flammability hazard rating (red diamond) for the storage location. Scale: 0 (will not burn) to 4 (extremely flammable). Drives fire suppression system design, electrical classification, and hot work permit requirements.',
    `nfpa_fire_diamond_health` STRING COMMENT 'NFPA 704 health hazard rating (blue diamond) for the storage location, indicating the degree of health hazard posed by materials stored here. Scale: 0 (no hazard) to 4 (deadly). Posted on location signage for emergency responder awareness.',
    `nfpa_fire_diamond_reactivity` STRING COMMENT 'NFPA 704 instability/reactivity hazard rating (yellow diamond) for the storage location. Scale: 0 (stable) to 4 (may detonate). Informs emergency response procedures and incompatible material segregation requirements.',
    `nfpa_fire_diamond_special` STRING COMMENT 'NFPA 704 special hazard symbol (white diamond) for the storage location. Common values: W (water reactive), OX (oxidizer), SA (simple asphyxiant). Empty if no special hazard applies. Used in emergency response planning and SDS alignment.. Valid values are `W|OX|SA|`',
    `osha_regulatory_citation` STRING COMMENT 'Applicable OSHA regulatory citation(s) governing safety requirements at this storage location (e.g., 29 CFR 1910.106 - Flammable Liquids, 29 CFR 1910.119 - PSM). Used for workplace safety compliance documentation and OSHA inspection readiness.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or distribution facility to which this warehouse location belongs. Aligns with SAP MM/EWM plant-warehouse structure for inventory valuation and materials management.. Valid values are `^[A-Z0-9]{1,10}$`',
    `rack` STRING COMMENT 'Alphanumeric identifier for the rack or bay within the aisle where this storage location is physically situated. Used in conjunction with aisle and level to precisely identify the bin coordinate.. Valid values are `^[A-Z0-9]{1,10}$`',
    `rotation_strategy` STRING COMMENT 'Inventory lot rotation strategy enforced at this storage location. FIFO (First In First Out) is standard for most materials; FEFO (First Expired First Out) is required for materials with expiration dates to prevent use of expired stock. Drives SAP EWM picking strategy configuration.. Valid values are `FIFO|FEFO|LIFO|manual`',
    `storage_condition_code` STRING COMMENT 'SAP MM/EWM storage condition code assigned to this location, used to match materials requiring specific storage conditions (e.g., flammable, corrosive, refrigerated, dry). Enforces material-location compatibility during putaway strategy execution.. Valid values are `^[A-Z0-9]{1,10}$`',
    `storage_section_code` STRING COMMENT 'SAP EWM storage section code grouping this location within the warehouse. Storage sections define areas with similar storage conditions (e.g., flammable liquids section, refrigerated section) and drive putaway and picking strategies.. Valid values are `^[A-Z0-9]{1,10}$`',
    `ventilation_class` STRING COMMENT 'Classification of the ventilation system installed at this storage location. Determines suitability for storing volatile organic compounds (VOCs), flammable vapors, and hazardous air pollutants (HAPs). Explosion-proof ventilation is required for Class I flammable liquid storage per NFPA 30.. Valid values are `none|natural|mechanical_general|mechanical_local_exhaust|explosion_proof`',
    `warehouse_location_level` STRING COMMENT 'Vertical level or tier identifier within the rack or shelving structure (e.g., 01 for ground level, 02 for second tier). Used for ergonomic storage assignment and weight-bearing capacity management.. Valid values are `^[A-Z0-9]{1,10}$`',
    `warehouse_number` STRING COMMENT 'SAP EWM warehouse number identifying the logical warehouse complex to which this location belongs. Used for warehouse-level inventory management, transfer order processing, and EWM configuration.. Valid values are `^[A-Z0-9]{1,10}$`',
    CONSTRAINT pk_warehouse_location PRIMARY KEY(`warehouse_location_id`)
) COMMENT 'Master record for all physical and logical storage locations within the warehouse network, including bulk tank farms, drum storage areas, cold storage rooms, hazmat segregation zones, quarantine bays, and finished goods warehouses. Captures location code, storage type, capacity (volume/weight), temperature range, humidity range, ventilation class, hazard class compatibility, NFPA fire diamond rating, incompatible hazard class segregation rules, maximum storage quantity per zone, fire zone, EPA/OSHA regulatory citations, and SAP EWM storage section mapping. Governs where specific chemical materials may be stored based on GHS/NFPA compatibility rules and required storage conditions.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`lot` (
    `lot_id` BIGINT COMMENT 'Primary key for lot',
    `supply_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the lot (batch) master record in the Silver Layer lakehouse. Primary key for all downstream joins and traceability chains.',
    `campaign_plan_id` BIGINT COMMENT 'Foreign key linking to planning.campaign_plan. Business justification: Chemical manufacturing uses campaign production where multiple lots are produced in a single campaign run. Lots must reference the campaign plan for campaign yield analysis, regulatory batch records, ',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Lot traceability requires association with the chemical product for quality release, regulatory reporting, and batch‑level SDS reference.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Production cost object controlling: lots produced or received are assigned to cost centers for cost allocation and production cost reporting. Standard SAP CO requirement in chemical manufacturing — lo',
    `manufacturing_order_id` BIGINT COMMENT 'Reference to the production order or process order under which this lot was manufactured. Null for externally procured lots. Maps to SAP Production Order (AUFNR) in PP.',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the chemical substance, intermediate, finished good, or packaging material associated with this lot. Maps to SAP Material Number (MATNR).',
    `material_specification_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.material_specification. Business justification: QC lot release in chemical manufacturing requires comparing lot test results against the active material specification version at time of receipt. This direct FK enables lot disposition reporting, CoA',
    `process_order_id` BIGINT COMMENT 'Foreign key linking to production.process_order. Business justification: In chemical manufacturing, a process order directly generates a production lot. Lot already links to manufacturing_order, but process_order is the execution-level entity that creates the lot. Required',
    `production_plant_id` BIGINT COMMENT 'Reference to the manufacturing plant or receiving facility where this lot was produced or first received. Maps to SAP Plant (WERKS) in MM/PP.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to supply.purchase_order. Business justification: Needed to link each production lot to its supplying purchase order, enabling lot‑level traceability for compliance audits and quality investigations.',
    `quality_specification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_specification. Business justification: Every inventory lot in chemical manufacturing is produced or received against a specific quality specification defining grade, purity, and regulatory requirements. This FK enables lot-level spec trace',
    `safety_data_sheet_id` BIGINT COMMENT 'Foreign key linking to ehs.safety_data_sheet. Business justification: GHS/OSHA HazCom 2012 compliance requires that each chemical lot is associated with the specific SDS version in effect at time of manufacture or receipt. Direct FK captures version-specific compliance ',
    `sds_record_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.sds_record. Business justification: Chemical manufacturing requires SDS access at the lot level for hazmat handling, storage compatibility verification, and emergency response. QC and warehouse staff reference the SDS when receiving, re',
    `standard_cost_id` BIGINT COMMENT 'Foreign key linking to finance.standard_cost. Business justification: Lot-level inventory valuation and COGS calculation: each chemical lot is valued at a standard cost record for financial reporting, variance analysis, and cost-of-goods-sold posting. Chemical manufactu',
    `vendor_id` BIGINT COMMENT 'Reference to the external supplier or vendor from whom this lot was received, applicable when lot origin is external procurement. Null for internally produced lots. Maps to SAP Vendor (LIFNR).',
    `vendor_site_id` BIGINT COMMENT 'Foreign key linking to supply.vendor_site. Business justification: GMP compliance and recall management in chemical manufacturing require tracing lots to the specific vendor manufacturing site, not just the vendor. Lot-to-vendor_site enables site-specific quality aud',
    `warehouse_location_id` BIGINT COMMENT 'Reference to the warehouse storage location or tank farm bin where this lot is currently physically stored. Maps to SAP Storage Location (LGORT) and SAP EWM storage bin.',
    `coc_number` STRING COMMENT 'The document reference number of the Certificate of Compliance (COC) issued for this lot, attesting conformance to customer-specified or regulatory requirements beyond standard QC testing (e.g., REACH compliance, RoHS, food-contact suitability). Distinct from COA which covers analytical results.. Valid values are `^[A-Z0-9-]{1,40}$`',
    `country_of_origin` STRING COMMENT 'The ISO 3166-1 alpha-3 country code of the country where this lot was manufactured or, for natural raw materials, where it was extracted. Required for customs declarations, import/export compliance, trade preference certificates, and REACH/TSCA regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this lot master record was first created in the source system (SAP MM Batch Master or LabWare LIMS), recorded in ISO 8601 format with timezone offset. Supports audit trail, data lineage, and GMP record-keeping requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the inventory_valuation_price (e.g., USD, EUR). Required for multi-currency financial reporting and FASB/IFRS compliance.. Valid values are `^[A-Z]{3}$`',
    `current_quantity` DECIMAL(18,2) COMMENT 'The remaining unreserved quantity of material currently available in this lot, updated with each inventory movement (goods issue, transfer, adjustment). Supports real-time stock position reporting and FIFO/FEFO allocation.',
    `days_to_expiry_threshold` STRING COMMENT 'The number of days before expiration at which this lot should trigger an inventory alert for proactive disposition, customer notification, or markdown action. Configured per material type and customer contract requirements. Used by FEFO rotation and expiry management workflows.',
    `disposition_status` STRING COMMENT 'Current quality disposition of the lot governing whether it may be used, shipped, or must be held. Released: QC-approved for use/sale. Quarantined: held pending QC decision. Rejected: failed QC and must be destroyed or reworked. Expired: past expiration date. Under Review: Out-of-Specification (OOS) or Out-of-Trend (OOT) investigation in progress. Recalled: subject to active recall action. Maps to SAP QM Usage Decision (VRBWG).. Valid values are `released|quarantined|rejected|expired|under_review|recalled`',
    `expiration_date` DATE COMMENT 'The date after which this lot must not be used, sold, or shipped. Calculated from manufacture date plus approved shelf-life period or assigned by QA based on stability data. Central to FEFO (First Expired First Out) inventory rotation logic. Maps to SAP Batch Expiration Date (VFDAT).',
    `gmp_status` STRING COMMENT 'Indicates whether this lot was manufactured under Good Manufacturing Practice (GMP) conditions as required for pharmaceutical-grade, food-contact, or regulated chemical applications. Drives customer-specific COA declarations and regulatory submissions.. Valid values are `gmp_compliant|non_gmp|gmp_pending_review`',
    `goods_receipt_date` DATE COMMENT 'The date this lot was physically received into the warehouse or plant, recorded at goods receipt posting in SAP MM. For internally produced lots, this is the date the finished goods were transferred to the warehouse. Maps to SAP MIGO Goods Receipt Posting Date (BUDAT).',
    `grade` STRING COMMENT 'Quality grade classification assigned to this lot based on QC test results and intended end-use application. Prime: meets full specification. Off-grade: meets reduced specification for alternative use. Technical/Pharmaceutical/Food/Agricultural grades reflect regulatory and customer-specific quality tiers. Drives pricing and customer allocation.. Valid values are `prime|off_grade|technical|pharmaceutical|food_grade|agricultural`',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether this lot is classified as a hazardous material requiring special storage, handling, labelling, and transport compliance under DOT, OSHA, and GHS regulations. Triggers hazmat storage location validation in SAP EWM.',
    `initial_quantity` DECIMAL(18,2) COMMENT 'The total quantity of material in this lot at the time of creation (production completion or goods receipt). Expressed in the base unit of measure of the material. Used as the denominator for yield calculations and lot consumption tracking.',
    `inventory_valuation_price` DECIMAL(18,2) COMMENT 'The per-unit valuation price applied to this lot for inventory accounting purposes, expressed in the companys functional currency. Used for COGS calculation, inventory write-down assessment, and financial reporting. Maps to SAP Moving Average Price or Standard Price (VERPR/STPRS) in FI/CO.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this lot master record in the source system. Used for incremental data pipeline processing, audit trail compliance, and detecting stale records in the Silver Layer.',
    `lot_number` STRING COMMENT 'Externally-known alphanumeric batch/lot identifier assigned at production or goods receipt. Used on Certificate of Analysis (COA), Certificate of Compliance (COC), shipping documents, and regulatory submissions. Maps to SAP Batch Number (CHARG) in MM/QM.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `manufacture_date` DATE COMMENT 'The date on which production of this lot was completed or, for externally received lots, the date of manufacture as declared by the supplier. Basis for shelf-life and expiration date calculation. Maps to SAP Batch Manufacturing Date (HSDAT).',
    `moisture_content_percent` DECIMAL(18,2) COMMENT 'The measured moisture content of this lot expressed as a percentage by weight, as determined by QC testing (e.g., Karl Fischer titration, loss on drying). Critical for solid and powder chemical products where moisture affects stability, reactivity, and product performance.',
    `nfpa_fire_rating` STRING COMMENT 'NFPA 704 flammability hazard rating (0-4) for the material in this lot. 0 = will not burn; 4 = will rapidly vaporize at normal conditions. Used for storage location assignment, fire suppression system design, and emergency response planning.',
    `origin` STRING COMMENT 'Indicates whether this lot was created through internal manufacturing, received from an external supplier, produced via rework/reprocessing of a non-conforming lot, or originated from a customer return. Drives traceability and regulatory reporting workflows.. Valid values are `internal_production|external_receipt|rework|reprocess|returned_goods`',
    `ph_value` DECIMAL(18,2) COMMENT 'The measured pH (Potential of Hydrogen) of this lot as determined by QC laboratory testing. Critical quality parameter for chemical products; drives corrosivity classification, storage material compatibility, and regulatory classification under GHS/DOT. Sourced from LabWare LIMS COA results.',
    `purity_percent` DECIMAL(18,2) COMMENT 'The measured purity of the primary chemical substance in this lot expressed as a percentage by weight or volume, as determined by QC analytical testing. Key quality attribute for pricing, formulation accuracy, and regulatory compliance. Sourced from LabWare LIMS COA.',
    `qc_release_date` DATE COMMENT 'The date on which the Quality Assurance function formally released this lot from quarantine to unrestricted use following successful completion of all required QC testing. Populated from LabWare LIMS usage decision timestamp. Critical for lead-time and cycle-time analytics.',
    `quarantine_flag` BOOLEAN COMMENT 'Boolean indicator that this lot is currently under quarantine and must not be issued, shipped, or consumed until released by Quality Assurance. Complements disposition_status for rapid system-level blocking in SAP EWM and WMS pick operations.',
    `recall_flag` BOOLEAN COMMENT 'Indicates whether this lot is subject to an active product recall or market withdrawal action. When True, triggers immediate inventory blocking in SAP EWM, customer notification workflows, and regulatory reporting to FDA/EPA/ECHA as applicable.',
    `restricted_substance_flag` BOOLEAN COMMENT 'Indicates whether this lot contains substances subject to regulatory restriction or authorization under REACH SVHC (Substances of Very High Concern), TSCA, or RoHS. Triggers compliance review before shipment to regulated markets.',
    `retest_date` DATE COMMENT 'The date by which this lot must be retested by the QC laboratory to confirm continued conformance to specification before further use or shipment. Applicable to raw materials and intermediates with defined retest intervals. Maps to SAP Batch Next Inspection Date (PRÜFDATUM).',
    `shelf_life_days` STRING COMMENT 'The total approved shelf life of this lot expressed in days, as defined by the material specification or stability study. Used to validate expiration date assignment and to support shelf-life remaining calculations for customer order fulfillment. Maps to SAP Material Master Total Shelf Life (MHDRZ).',
    `supplier_lot_number` STRING COMMENT 'The original lot or batch number assigned by the external supplier, as printed on the supplier COA and shipping documents. Maintained alongside the internal lot_number for full traceability back to the suppliers manufacturing records. Null for internally produced lots.. Valid values are `^[A-Z0-9-/]{1,40}$`',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which lot quantities are expressed (e.g., KG for kilograms, L for litres, MT for metric tonnes). Aligns with SAP Base Unit of Measure (MEINS) on the material master. Required for all quantity-based calculations and regulatory reporting. [ENUM-REF-CANDIDATE: KG|LB|L|GAL|MT|G|M3|BBL|EA|BAG — 10 candidates stripped; promote to reference product]',
    `voc_content_ppm` DECIMAL(18,2) COMMENT 'The measured or declared Volatile Organic Compound (VOC) content of this lot expressed in Parts Per Million (PPM) by weight. Required for EPA air emissions reporting, state VOC regulations, and customer environmental product declarations. Sourced from QC analytical results in LabWare LIMS.',
    CONSTRAINT pk_lot PRIMARY KEY(`lot_id`)
) COMMENT 'Lot (batch) master record representing a discrete quantity of a chemical material produced or received under uniform conditions. Captures lot number, material reference, manufacturing date, expiration date, retest date, days-to-expiry threshold, COA reference, GMP status, quarantine flag, lot origin (internal production vs. external receipt), current disposition (released, quarantined, rejected, expired), shelf-life remaining calculation basis, and country-of-origin for regulatory reporting. Central to FIFO/FEFO rotation, full traceability, recall management, and regulatory compliance (FDA, REACH, TSCA). Integrates with LabWare LIMS for QC release status.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`stock_movement` (
    `stock_movement_id` BIGINT COMMENT 'Unique surrogate identifier for each inventory movement event record in the silver layer lakehouse. Primary key for the stock_movement data product.',
    `batch_record_id` BIGINT COMMENT 'Foreign key linking to production.batch_record. Business justification: Stock movements in chemical manufacturing are directly triggered by batch confirmations (goods receipt from production, goods issue to production). Direct FK enables movement-to-batch traceability for',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Needed for posting inventory movements to the correct cost center in the Cost Center Allocation report.',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to supply.goods_receipt. Business justification: Goods receipt movements (movement type 101) in chemical manufacturing generate stock movements. Linking stock_movement to goods_receipt provides a complete audit trail from supplier delivery to invent',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Goods movement to financial posting reconciliation: in SAP-based chemical manufacturing, every stock movement generates a corresponding FI journal entry. Linking enables period-end reconciliation betw',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: Stock movement must be linked to the lot it moves; replace string lot_number with FK lot_id for traceability.',
    `manufacturing_order_id` BIGINT COMMENT 'Foreign key linking to production.manufacturing_order. Business justification: Stock movements (goods issue/receipt) are posted against manufacturing orders in chemical plant ERP systems. This is a fundamental production-inventory integration point for order cost settlement, mat',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.material_master. Business justification: Inventory movement reporting, hazmat movement logs, and regulatory material tracking (TSCA, REACH) require direct material_master reference on each movement record. stock_movement.material_number is a',
    `outbound_delivery_id` BIGINT COMMENT 'Foreign key linking to order.outbound_delivery. Business justification: Required for the Delivery Execution report to trace which stock movements belong to each outbound delivery for compliance and audit.',
    `planned_order_id` BIGINT COMMENT 'Foreign key linking to planning.planned_order. Business justification: Goods receipts and goods issues in inventory are triggered by planned orders converted to execution documents. Linking stock movements to originating planned orders enables MRP reconciliation, supply ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Supports profit center profitability analysis of inventory movements for internal management reporting.',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: Every stock movement event affects a specific stock position (updating on_hand_quantity, reserved_quantity, etc.). Adding stock_position_id FK to inventory.stock_position creates a direct audit trail ',
    `transfer_order_id` BIGINT COMMENT 'Foreign key linking to inventory.transfer_order. Business justification: Link stock movement to its originating transfer order for end‑to‑end tracking; replace free‑text field with FK.',
    `usage_decision_id` BIGINT COMMENT 'Foreign key linking to quality.usage_decision. Business justification: Usage decisions in QM directly post stock movements (unrestricted/blocked/scrap). This is the core SAP QM-MM integration in chemical manufacturing. Every quality-driven stock posting must reference th',
    `warehouse_location_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse_location. Business justification: Stock movement must reference the source warehouse location entity for accurate location tracking and audit reporting.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Core SAP MM/PM integration: chemicals and materials issued from inventory to maintenance work orders (goods issue movement type 261) must reference the consuming work order. This supports maintenance ',
    `created_timestamp` TIMESTAMP COMMENT 'The exact date and time when the stock movement record was first captured and persisted in the system. Used for audit trail, data lineage, and FIFO/FEFO sequencing validation. Corresponds to SAP CPUDT + CPUTM fields combined.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the movement_amount valuation (e.g., USD, EUR, GBP). Corresponds to SAP WAERS field. Required for multi-currency chemical manufacturing operations with global procurement and sales.. Valid values are `^[A-Z]{3}$`',
    `destination_storage_location` STRING COMMENT 'The SAP storage location code (Lagerort) to which the material is being moved or received. Represents the target warehouse area, tank farm zone, production staging area, or quarantine location. Null for pure outbound goods issues with no destination location within the plant.',
    `document_date` DATE COMMENT 'The date on the physical or external source document (e.g., vendor delivery note, production order confirmation) that triggered the inventory movement. May differ from posting_date when documents are processed with a lag. Corresponds to SAP BLDAT field.',
    `expiration_date` DATE COMMENT 'The expiration or shelf-life end date of the lot/batch being moved. Used for FEFO (First Expired First Out) lot rotation enforcement, quarantine triggering for expired materials, and regulatory compliance. Corresponds to SAP VFDAT (shelf life expiration date) on the batch master. Critical for chemical raw materials, intermediates, and finished goods with defined shelf lives.',
    `fifo_fefo_validation_result` STRING COMMENT 'The result of the FIFO (First In First Out) or FEFO (First Expired First Out) lot rotation validation check performed at the time of goods issue. Passed = correct lot selected per rotation policy; Failed = incorrect lot selected, violating rotation rules; Not Applicable = movement type does not require lot rotation validation (e.g., goods receipt); Overridden = FIFO/FEFO rule was manually overridden with documented justification. Critical for chemical product quality, shelf-life management, and GMP compliance.. Valid values are `passed|failed|not_applicable|overridden`',
    `goods_receipt_blocked` BOOLEAN COMMENT 'Indicates whether this goods receipt movement was posted to GR blocked stock (Wareneingang gesperrt), meaning the material has been physically received but not yet released for use pending inspection or documentation review. True = posted to blocked GR stock; False = posted directly to unrestricted or inspection stock. Corresponds to SAP movement type 103/105 scenario.',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether the material being moved is classified as a hazardous material requiring special handling, storage, or transport compliance. True = hazardous material subject to EHS regulations (GHS, DOT, OSHA, EPA); False = non-hazardous material. Triggers hazmat storage compliance checks and EHS reporting requirements.',
    `material_document_number` STRING COMMENT 'The externally-known SAP material document number (Materialbelegs-nummer) assigned by SAP S/4HANA MM upon posting the inventory movement. Serves as the primary business identifier linking back to the source system transaction. Equivalent to MBLNR in SAP.',
    `material_document_year` STRING COMMENT 'The fiscal year in which the material document was posted in SAP S/4HANA MM. Combined with material_document_number forms the unique SAP document key (MBLNR + MJAHR).',
    `movement_amount` DECIMAL(18,2) COMMENT 'The inventory valuation amount (in local currency) associated with this stock movement, representing the financial impact on inventory accounts. Calculated as quantity multiplied by the moving average price or standard price at time of posting. Used for COGS (Cost of Goods Sold) reporting, inventory valuation, and FI/CO integration. Corresponds to SAP DMBTR field.',
    `movement_category` STRING COMMENT 'High-level business classification of the inventory movement event. Goods Receipt (GR) covers inbound receipts from vendors or production; Goods Issue (GI) covers consumption or outbound shipments; Stock Transfer covers location-to-location moves; Return covers vendor or customer returns; Scrapping covers material write-offs; Sampling covers quality lab withdrawals; Revaluation covers price or valuation adjustments. Subsumes formerly separate goods_receipt and goods_issue records as movement subtypes. [ENUM-REF-CANDIDATE: goods_receipt|goods_issue|stock_transfer|return|scrapping|sampling|revaluation — promote to reference product]',
    `movement_direction` STRING COMMENT 'Directional classification of the inventory movement relative to the plant or warehouse: inbound (stock entering the facility, e.g., goods receipt), outbound (stock leaving the facility, e.g., goods issue to customer or production), or internal (stock moving within the facility, e.g., storage location transfer). Used for net stock position calculations and directional reporting.. Valid values are `inbound|outbound|internal`',
    `movement_reason_code` STRING COMMENT 'A coded reason explaining why the inventory movement occurred, beyond what the movement type conveys. Examples include: production consumption, quality rejection, customer return, vendor return, cycle count adjustment, process loss, sampling withdrawal, spillage/waste, regulatory disposal. Corresponds to SAP GRUND field. [ENUM-REF-CANDIDATE: production_consumption|quality_rejection|customer_return|vendor_return|cycle_count_adjustment|process_loss|sampling|spillage|regulatory_disposal — promote to reference product]',
    `movement_reason_text` STRING COMMENT 'Free-text description providing additional context or explanation for the inventory movement reason, supplementing the movement_reason_code. Used for exception documentation, CAPA (Corrective and Preventive Action) linkage, and audit trail narratives. Corresponds to SAP text fields associated with GRUND.',
    `movement_status` STRING COMMENT 'Current lifecycle status of the stock movement record. Posted = successfully committed to inventory books; Reversed = cancelled by a subsequent reversal posting; Blocked = movement is on hold pending approval or investigation; Pending Approval = movement requires workflow approval before final posting (e.g., high-value scrapping). Supports workflow management and audit compliance.. Valid values are `posted|reversed|blocked|pending_approval`',
    `movement_type_code` STRING COMMENT 'SAP movement type code (Bewegungsart) that classifies the inventory transaction. Standard codes include 101 (Goods Receipt for PO), 122 (Return to Vendor), 201 (Goods Issue to Cost Center), 261 (Goods Issue for Production Order), 301 (Transfer Posting), 551 (Scrapping), 601 (Goods Issue for Delivery), 701 (Inventory Difference). Replaces the former movement_type reference table as an embedded code per product design. [ENUM-REF-CANDIDATE: 101|122|201|261|301|551|601|701|... — promote to reference product]',
    `order_unit_of_measure` STRING COMMENT 'The unit of measure used in the reference order document (purchase order, sales order, or production order) for this movement. Corresponds to SAP ERFME field. Enables reconciliation between order quantities and inventory quantities when UOM conversion applies.',
    `plant_code` STRING COMMENT 'SAP plant code (Werk) identifying the manufacturing or distribution facility where the inventory movement occurred. In chemical manufacturing, plants correspond to production sites, tank farms, or distribution centers. Serves as the primary organizational unit for inventory management.',
    `posting_date` DATE COMMENT 'The principal business event date on which the inventory movement was officially posted to the books in SAP S/4HANA MM (Buchungsdatum - BUDAT). This is the date used for inventory valuation, financial period assignment, and regulatory reporting. Distinct from the document creation timestamp.',
    `quantity` DECIMAL(18,2) COMMENT 'The quantity of material involved in the inventory movement, expressed in the base unit of measure. Positive values represent inbound or internal movements; negative values represent outbound or consumption movements per SAP convention. Supports up to 4 decimal places for precision chemical measurements (e.g., kg, L, mol).',
    `quantity_in_order_uom` DECIMAL(18,2) COMMENT 'The movement quantity expressed in the order unit of measure (e.g., purchase order UOM or sales order UOM), which may differ from the base unit of measure. For example, a material ordered in drums (DR) but managed in kilograms (KG). Corresponds to SAP ERFMG field.',
    `quarantine_flag` BOOLEAN COMMENT 'Indicates whether the material involved in this movement is under quarantine status at the time of the movement. True = material is quarantined (e.g., pending QC release, OOS investigation, regulatory hold, contamination suspicion); False = material is not under quarantine. Supports hazardous material storage compliance and GMP quality hold management.',
    `reference_document_item` STRING COMMENT 'The line item number within the reference document (e.g., PO line item, production order component line) associated with this inventory movement. Combined with reference_document_number provides precise traceability to the originating document line. Corresponds to SAP EBELP (PO item) field.',
    `reference_document_number` STRING COMMENT 'The number of the originating reference document (e.g., Purchase Order number, Production Order number, Sales Order number, Delivery number) that triggered this inventory movement. Provides the complete audit trail linking inventory movements back to procurement, production, or sales transactions. Corresponds to SAP EBELN (PO) or AUFNR (order) depending on context.',
    `reference_document_type` STRING COMMENT 'The type of the originating business document that triggered this inventory movement. Purchase Order (PO) for vendor receipts; Production Order or Process Order for manufacturing consumption/receipt; Sales Order for customer-specific stock; Delivery for outbound shipments; Transfer Order for warehouse transfers; Reservation for planned withdrawals. [ENUM-REF-CANDIDATE: purchase_order|production_order|sales_order|delivery|transfer_order|process_order|reservation — promote to reference product]',
    `reversal_flag` BOOLEAN COMMENT 'Indicates whether this stock movement record is a reversal (cancellation) of a previously posted movement. True = this document is a reversal posting that negates a prior movement; False = original movement. Essential for net inventory position calculations and audit trail integrity.',
    `reversed_document_number` STRING COMMENT 'The material document number of the original movement that this record reverses, when reversal_flag is True. Enables bidirectional audit trail linking between original and reversal postings. Corresponds to SAP STBLG field.',
    `source_plant_code` STRING COMMENT 'The SAP plant code of the sending plant for inter-plant stock transfer movements (STO - Stock Transfer Orders). Populated only for cross-plant transfers. Corresponds to SAP UMWRK field.',
    `special_stock_indicator` STRING COMMENT 'SAP special stock indicator (SOBKZ) identifying non-standard stock ownership or custody arrangements. E = Sales Order Stock (make-to-order), K = Consignment Stock at Customer, Q = Project Stock, V = Consignment Stock from Vendor, W = Returnable Transport Packaging. Empty for standard own stock. Critical for chemical toll manufacturing and consignment inventory scenarios.. Valid values are `E|K|Q|V|W|`',
    `stock_type` STRING COMMENT 'The SAP stock type category indicating the usability status of the inventory being moved. Unrestricted stock is available for use; Quality Inspection stock is under QC hold pending COA approval; Blocked stock is restricted from use (e.g., OOS - Out of Specification); Restricted stock has conditional use limitations; Returns stock is customer-returned material awaiting disposition. Corresponds to SAP SOBKZ / INSMK fields.. Valid values are `unrestricted|quality_inspection|blocked|restricted|returns`',
    `unit_of_measure` STRING COMMENT 'The base unit of measure for the movement quantity (e.g., KG for kilograms, L for liters, MT for metric tons, EA for each, DR for drums, IBC for intermediate bulk containers). Corresponds to SAP MEINS (base UOM) field. Critical for chemical inventory accuracy and regulatory reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when the stock movement record was last modified in the source system or lakehouse silver layer. Supports incremental data loading, change detection, and audit compliance.',
    `valuation_type` STRING COMMENT 'SAP valuation type (Bewertungsart - BWTAR) used when a material is managed with split valuation — for example, differentiating between domestic-sourced and imported raw materials, or between different quality grades of the same chemical. Enables separate inventory valuation for the same material number.',
    CONSTRAINT pk_stock_movement PRIMARY KEY(`stock_movement_id`)
) COMMENT 'Transactional record of every inventory movement event including goods receipts (GR), goods issues (GI), stock transfers, returns, scrapping, sampling, and revaluations. Captures movement type code (replacing the former movement_type reference table), material, lot number, quantity, unit of measure, source location, destination location, movement direction (inbound/outbound/internal), movement reason, reference document (PO, production order, sales order, delivery), posting date, posting user, and FIFO/FEFO lot selection validation result. Provides the complete audit trail for all inventory changes. Subsumes formerly separate goods_receipt and goods_issue records as movement subtypes.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`transfer_order` (
    `transfer_order_id` BIGINT COMMENT 'Unique surrogate identifier for the warehouse transfer order record in the Databricks Silver Layer. Primary key for this entity.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Assigns inter‑warehouse transfer orders to cost centers for budgeting and expense tracking.',
    `line_item_id` BIGINT COMMENT 'Foreign key linking to order.line_item. Business justification: Inter‑plant transfer orders are often created to fulfill a particular sales order line; linking enables the Transfer Fulfillment tracking report.',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: transfer_order moves a specific lot from one bin/location to another. The lot_number STRING column is denormalized; adding lot_id FK to inventory.lot normalizes this. One lot can have multiple transfe',
    `material_master_id` BIGINT COMMENT 'Reference to the material (raw material, intermediate, finished good, or packaging) being physically moved by this transfer order. Aligns with SAP MM material master.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to planning.production_schedule. Business justification: Transfer orders in chemical plants are generated to stage raw materials and intermediates to production areas per the production schedule. This link enables schedule-driven warehouse execution reporti',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Inter-segment cost allocation: transfer orders crossing profit center boundaries require profit center assignment for intercompany/inter-segment accounting. Chemical manufacturing segment reporting re',
    `storage_bin_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_bin. Business justification: transfer_order has source_bin (STRING) representing the origin bin. Adding source_storage_bin_id FK to inventory.storage_bin normalizes the source bin reference, enabling bin-level capacity tracking a',
    `warehouse_location_id` BIGINT COMMENT 'Reference to the warehouse complex within which this transfer order is executed. Scopes the source and destination bins to a single warehouse facility.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Date and time when the operator physically began executing the transfer order (e.g., first scan of source bin or handling unit). Enables measurement of queue wait time and operator response time.',
    `cancellation_reason` STRING COMMENT 'Free-text or coded reason for cancellation of the transfer order (e.g., material not found at source bin, bin blocked, production order cancelled, duplicate order). Supports root cause analysis and process improvement.',
    `cancellation_timestamp` TIMESTAMP COMMENT 'Date and time when the transfer order was cancelled in SAP EWM. Populated only when transfer_order_status = cancelled. Used for exception reporting and warehouse efficiency analysis.',
    `confirmation_method` STRING COMMENT 'Method used by the operator or system to confirm execution of the transfer order. rf_scan = RF barcode/RFID scanner; manual = paper-based or keyboard entry; automated_conveyor = conveyor system auto-confirmation; voice_picking = voice-directed warehouse system; agv = automated guided vehicle.. Valid values are `rf_scan|manual|automated_conveyor|voice_picking|agv`',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'Actual quantity confirmed as physically moved by the operator upon transfer order completion. May differ from transfer_quantity due to partial picks, short picks, or discrepancies discovered during execution.',
    `confirmed_timestamp` TIMESTAMP COMMENT 'Date and time when the transfer order was fully confirmed in SAP EWM, triggering the inventory goods movement posting. Represents the principal business event time for this transaction.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the transfer order was first created in SAP EWM. Represents the record audit creation time and the start of the transfer order lifecycle.',
    `destination_bin` STRING COMMENT 'Alphanumeric identifier of the specific storage bin, rack location, or tank to which the material is being moved. Represents the physical destination within the warehouse complex.',
    `destination_storage_section` STRING COMMENT 'SAP EWM storage section within the destination storage type, providing logical grouping of target bins.',
    `destination_storage_type` STRING COMMENT 'SAP EWM storage type code for the target location. Used to validate compatibility with material hazard classification and storage requirements (e.g., flammable, corrosive, oxidizer segregation per OSHA PSM and NFPA codes).',
    `expiration_date` DATE COMMENT 'Expiration or shelf-life expiry date of the material lot being transferred. Used to enforce FEFO (First Expired First Out) rotation rules and prevent movement of expired material to active storage. Critical for GMP compliance.',
    `goods_movement_document` STRING COMMENT 'SAP MM material document number generated upon posting of the inventory goods movement triggered by transfer order confirmation. Links the physical warehouse movement to the financial inventory posting in SAP FI/CO.',
    `gross_weight_kg` DECIMAL(18,2) COMMENT 'Total gross weight in kilograms of the material quantity being transferred, including packaging (drums, IBCs, pallets). Used for load planning, equipment capacity validation, and DOT hazmat transport documentation.',
    `hazard_class` STRING COMMENT 'GHS/DOT hazard classification of the material being transferred (e.g., Flammable Liquid Class 3, Corrosive, Oxidizer, Toxic). Drives storage segregation rules and emergency response procedures. [ENUM-REF-CANDIDATE: flammable_liquid|corrosive|oxidizer|toxic|explosive|compressed_gas|environmental_hazard|none — promote to reference product]',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether the material being transferred is classified as hazardous under DOT, OSHA, or GHS regulations. When True, additional handling protocols, PPE requirements, and segregation rules apply. Supports EHS compliance reporting.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent modification to the transfer order record in SAP EWM (e.g., quantity change, operator reassignment, status update). Supports audit trail and change tracking.',
    `movement_type_code` STRING COMMENT 'SAP EWM/WM movement type code (e.g., 311, 312, 321) that drives the inventory posting logic and account determination in SAP FI/CO. Provides granular classification beyond the high-level transfer_type.',
    `planned_start_timestamp` TIMESTAMP COMMENT 'Scheduled date and time when the physical movement is planned to begin. Used for warehouse resource scheduling, shift planning, and SLA monitoring against production order requirements.',
    `priority` STRING COMMENT 'Numeric priority level assigned to the transfer order for warehouse queue management. Lower values indicate higher urgency (e.g., 1 = urgent production replenishment, 10 = routine reorganization). Used by SAP EWM task interleaving and resource optimization.',
    `quarantine_flag` BOOLEAN COMMENT 'Indicates whether the material lot being transferred is under quarantine status (e.g., pending QC release, OOS investigation, CAPA hold). When True, the transfer may only move material to a designated quarantine storage area. Aligns with SAP QM usage decision.',
    `reference_document_number` STRING COMMENT 'Number of the upstream triggering document that initiated this transfer order (e.g., production order number, delivery note, stock transport order, replenishment request). Provides end-to-end traceability from warehouse movement back to business process.',
    `reference_document_type` STRING COMMENT 'Type of the upstream document that triggered this transfer order. Enables classification of warehouse movements by business process origin for analytics and KPI reporting.. Valid values are `production_order|delivery|stock_transport_order|replenishment_request|manual`',
    `retest_date` DATE COMMENT 'Date by which the material lot must be retested by the QC laboratory before continued use. Distinct from expiration_date; a lot may be within shelf life but require periodic requalification per LIMS-managed testing schedules.',
    `source_storage_section` STRING COMMENT 'SAP EWM storage section within the source storage type, providing a logical grouping of bins (e.g., flammable liquids section, ambient section, cold storage section).',
    `source_storage_type` STRING COMMENT 'SAP EWM storage type code for the origin location (e.g., bulk storage, high-rack, tank farm, hazardous material cage, quarantine area). Determines handling rules and equipment requirements.',
    `source_system` STRING COMMENT 'Operational system of record from which this transfer order record was extracted. Supports data lineage tracking in the Databricks Silver Layer and distinguishes between SAP EWM (Extended Warehouse Management), legacy SAP WM, or manually created records.. Valid values are `SAP_EWM|SAP_WM|MANUAL`',
    `special_stock_indicator` STRING COMMENT 'SAP MM special stock type indicator identifying ownership or allocation of the material (e.g., consignment stock, project stock, sales-order-specific stock). Affects inventory valuation and availability checks.. Valid values are `own|consignment|project|sales_order|vendor_returnable`',
    `stock_category` STRING COMMENT 'SAP EWM/MM stock category of the material being transferred. Determines whether the stock is available for consumption or shipment. unrestricted = freely available; quality_inspection = pending QC release; blocked = not available for use; returns = returned goods; restricted = conditionally available.. Valid values are `unrestricted|quality_inspection|blocked|returns|restricted`',
    `storage_condition` STRING COMMENT 'Required storage condition code for the material (e.g., ambient, refrigerated, frozen, temperature-controlled, humidity-controlled, inert atmosphere). Validates that the destination bin meets material storage requirements. [ENUM-REF-CANDIDATE: ambient|refrigerated|frozen|temperature_controlled|humidity_controlled|inert_atmosphere|flammable_cabinet — promote to reference product]',
    `to_number` STRING COMMENT 'Externally visible alphanumeric transfer order number assigned by SAP EWM. This is the business-facing identifier used in warehouse operations, printed on pick/put-away documents, and referenced in MES and WMS communications.',
    `transfer_order_status` STRING COMMENT 'Current lifecycle state of the transfer order within SAP EWM. created = issued but not yet started; in_progress = operator has begun movement; partially_confirmed = partial quantity confirmed; confirmed = fully executed and goods movement posted; cancelled = voided before execution.. Valid values are `created|in_progress|partially_confirmed|confirmed|cancelled`',
    `transfer_quantity` DECIMAL(18,2) COMMENT 'Planned quantity of material to be moved as specified on the transfer order at creation time. Expressed in the base unit of measure of the material (e.g., KG, L, EA, MT).',
    `transfer_type` STRING COMMENT 'Classification of the warehouse movement purpose. replenishment = restocking a pick face from reserve storage; putaway = placing newly received goods into a bin; pick = retrieving goods for outbound delivery; internal_transfer = bin-to-bin move for reorganization or hazmat segregation; return_to_stock = returning goods from staging or production back to storage.. Valid values are `replenishment|putaway|pick|internal_transfer|return_to_stock`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the transfer and confirmed quantities (e.g., KG = kilograms, L = litres, MT = metric tonnes, EA = each, M3 = cubic metres). Aligns with SAP MM material master UOM. [ENUM-REF-CANDIDATE: KG|L|EA|MT|G|M3|LB|GAL — 8 candidates stripped; promote to reference product]',
    CONSTRAINT pk_transfer_order PRIMARY KEY(`transfer_order_id`)
) COMMENT 'Warehouse transfer order issued within SAP EWM to physically move stock from one storage bin or location to another within the same warehouse complex. Captures transfer order number, source bin, destination bin, material, lot, quantity, transfer type (replenishment, putaway, pick, internal transfer), priority, assigned operator, confirmation status, and execution timestamps. Distinct from inter-plant stock transfer orders which are logistics-domain events.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`quarantine_hold` (
    `quarantine_hold_id` BIGINT COMMENT 'Unique system-generated identifier for the quarantine or quality hold record. Primary key for this entity.',
    `batch_record_id` BIGINT COMMENT 'Foreign key linking to production.batch_record. Business justification: Quarantine holds in chemical manufacturing are directly triggered by batch failures or deviations. Linking quarantine_hold to batch_record enables direct traceability from inventory hold to the produc',
    `capa_id` BIGINT COMMENT 'Foreign key linking to quality.capa. Business justification: Quarantine holds in chemical manufacturing are resolved through CAPAs. capa_reference_number is a denormalized text field. A proper FK enables CAPA effectiveness tracking against inventory disposition',
    `case_id` BIGINT COMMENT 'Foreign key linking to customer.case. Business justification: In chemical mfg, customer complaints (cases) directly trigger quarantine holds on implicated inventory lots. The quarantine_hold table already stores customer_complaint_number as a plain text denormal',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Quarantine holds are placed on specific chemical products stock for QC failures, regulatory events, or EHS incidents. Linking to chemical_product enables product-level hold reporting, CAPA management',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Quality cost accountability: quarantine holds incur costs (storage, testing, disposal, CAPA) charged to cost centers. Chemical manufacturing quality departments track hold-related costs by cost center',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to supply.goods_receipt. Business justification: Quarantine holds in chemical manufacturing are frequently initiated upon goods receipt when incoming material fails inspection. Linking quarantine_hold to the triggering goods_receipt enables quality ',
    `incoming_inspection_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.incoming_inspection. Business justification: Quarantine holds in chemical manufacturing are frequently triggered by failed incoming inspections. Linking quarantine_hold to the triggering incoming_inspection record is essential for CAPA root caus',
    `inspection_lot_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_lot. Business justification: In chemical manufacturing, quarantine holds are directly triggered by QM inspection lots (goods receipt, in-process). The lims_inspection_lot_number plain-text field is a denormalized reference to ins',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: quarantine_hold is placed on a specific lot/batch. The lot_number STRING column is denormalized; adding lot_id FK to inventory.lot normalizes this and enables direct join to lot attributes (expiration',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the raw material, intermediate, finished good, or packaging material placed under quarantine hold.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to planning.production_schedule. Business justification: A quarantine hold on a raw material or intermediate directly threatens scheduled production runs in chemical manufacturing. Planners need to identify which production schedules are at risk due to held',
    `returns_order_id` BIGINT COMMENT 'Foreign key linking to product.returns_order. Business justification: In chemical manufacturing, customer returns trigger quarantine holds on returned material pending QC inspection and disposition (GMP requirement). Linking quarantine_hold to returns_order enables end-',
    `safety_incident_id` BIGINT COMMENT 'Foreign key linking to ehs.safety_incident. Business justification: Quarantine holds in chemical manufacturing are frequently initiated as a direct consequence of safety incidents (contamination events, spills, chemical exposure). Linking quarantine_hold to the trigge',
    `sds_record_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.sds_record. Business justification: Quarantine disposition decisions for hazardous materials require the current SDS to determine safe handling, storage, and disposal. quarantine_hold.sds_number is a plain-text denormalization; a proper',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: A quarantine hold is placed on a specific stock position (the exact quantity at a specific location). Adding stock_position_id FK to inventory.stock_position enables direct linkage between the hold an',
    `usage_decision_id` BIGINT COMMENT 'Foreign key linking to quality.usage_decision. Business justification: Quarantine hold disposition (release/reject/reprocess/destroy) is formally recorded as a QM usage decision in chemical manufacturing. This FK links the inventory quarantine resolution to the quality a',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier/vendor master record when the quarantined material was externally procured. Used for supplier quality performance tracking and return-to-supplier disposition workflows.',
    `warehouse_location_id` BIGINT COMMENT 'Reference to the warehouse or tank farm location where the quarantined stock is physically stored. Links to the warehouse master in SAP EWM.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Quarantine holds in chemical manufacturing are frequently initiated by equipment failures and resolved through corrective maintenance work orders. CAPA and disposition workflows require traceability f',
    `actual_resolution_date` DATE COMMENT 'Actual date on which the quarantine hold was resolved through release, rejection, or administrative closure. Compared against target resolution date for performance reporting.',
    `affected_quantity_rejected` DECIMAL(18,2) COMMENT 'Quantity of the originally held material that was condemned, destroyed, or returned to supplier following disposition. Together with affected_quantity_released, accounts for the full hold quantity.',
    `affected_quantity_released` DECIMAL(18,2) COMMENT 'Quantity of the originally held material that was ultimately released for use or shipment following disposition. May be less than hold_quantity if partial release was approved (e.g., after rework or resampling).',
    `batch_number` STRING COMMENT 'Production batch number associated with the quarantined material, as recorded in the Manufacturing Execution System (MES) or SAP PP. May differ from lot number when multiple batches are consolidated into a single lot.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the quarantine hold record was first created in the data platform. Used for audit trail and data lineage.',
    `disposition_decision` STRING COMMENT 'Final disposition outcome for the quarantined material: released = approved for use or shipment; rejected = condemned and removed from usable stock; rework = returned to production for reprocessing; retest = additional testing required before final decision; return_to_supplier = returned to vendor; destroy = material to be destroyed per EHS protocols; conditional_release = released with documented restrictions. [ENUM-REF-CANDIDATE: released|rejected|rework|retest|return_to_supplier|destroy|conditional_release — 7 candidates stripped; promote to reference product]',
    `disposition_justification` STRING COMMENT 'Free-text narrative documenting the technical and business rationale for the disposition decision. Required for GMP compliance and regulatory audit readiness.',
    `disposition_timestamp` TIMESTAMP COMMENT 'Date and time when the disposition decision was formally approved and recorded. Distinct from actual resolution date; captures the precise moment of authorization.',
    `escalation_date` DATE COMMENT 'Date on which the quarantine hold was escalated to senior management or regulatory affairs. Null if escalation_flag is false.',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether the quarantine hold has been escalated to senior QA management, regulatory affairs, or executive leadership due to severity, regulatory implications, or breach of target resolution date.',
    `expiration_date` DATE COMMENT 'Expiration or retest date of the quarantined lot as assigned during manufacturing or receipt. Critical for FEFO (First Expired First Out) inventory management and determining if material has expired during the hold period.',
    `ghs_hazard_class` STRING COMMENT 'GHS hazard classification of the quarantined material (e.g., Flammable Liquid Cat 2, Acute Toxicity Cat 3, Corrosive). Required for safe storage and handling during quarantine and for EHS compliance reporting.',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the quarantined material is classified as hazardous under GHS, DOT, or OSHA standards. Drives special handling, storage segregation, and disposal requirements during the hold period.',
    `hold_date` TIMESTAMP COMMENT 'The date and timestamp when the quarantine hold was formally placed on the material or lot. Represents the principal business event time for this transaction.',
    `hold_duration_days` STRING COMMENT 'Number of calendar days the quarantine hold was active, calculated from hold_date to actual_resolution_date. Used for inventory aging analysis, SLA compliance reporting, and process improvement KPIs.',
    `hold_number` STRING COMMENT 'Externally-known, human-readable reference number assigned to the quarantine hold at initiation (e.g., QH-2024-000123). Used in cross-functional communications, LIMS, and EHS systems.. Valid values are `^QH-[0-9]{4}-[0-9]{6}$`',
    `hold_quantity` DECIMAL(18,2) COMMENT 'Quantity of material placed under quarantine hold. Represents the principal quantitative fact of this hold record. Must be expressed in the base unit of measure for the material.',
    `hold_quantity_uom` STRING COMMENT 'Unit of measure for the hold quantity (e.g., KG for kilograms, L for liters, MT for metric tons, DRUM for drum containers). Aligns with SAP base unit of measure (MEINS). [ENUM-REF-CANDIDATE: KG|LB|L|GAL|MT|TON|EA|BAG|DRUM|IBC — 10 candidates stripped; promote to reference product]',
    `hold_reason_code` STRING COMMENT 'Standardized code indicating the primary reason for the quarantine hold. OOS = Out of Specification; OOT = Out of Trend; CUSTOMER_COMPLAINT = customer-reported quality issue; REGULATORY_HOLD = regulatory agency directive; DAMAGE = physical damage; CONTAMINATION = cross-contamination or foreign material; LABEL_ERROR = incorrect or missing labeling; PENDING_COA = Certificate of Analysis (COA) not yet received. [ENUM-REF-CANDIDATE: OOS|OOT|CUSTOMER_COMPLAINT|REGULATORY_HOLD|DAMAGE|CONTAMINATION|LABEL_ERROR|PENDING_COA — promote to reference product]',
    `hold_reason_description` STRING COMMENT 'Free-text narrative describing the specific reason for placing the material under quarantine hold. Provides context beyond the hold reason code, including test failure details, complaint summary, or regulatory directive reference.',
    `hold_status` STRING COMMENT 'Current lifecycle state of the quarantine hold. open indicates active restriction; released indicates disposition approved for use/shipment; rejected indicates material condemned or destroyed; pending_review awaits disposition decision; escalated requires senior QA or regulatory review; closed is administratively finalized.. Valid values are `open|released|rejected|pending_review|escalated|closed`',
    `hold_type` STRING COMMENT 'Classification of the quarantine hold by originating function: quality for QC/QA-initiated holds; regulatory for holds triggered by EPA, OSHA, or ECHA directives; safety for EHS-initiated holds; customer for customer complaint-driven holds; environmental for environmental compliance holds; administrative for documentation or system-related holds.. Valid values are `quality|regulatory|safety|customer|environmental|administrative`',
    `initiating_system` STRING COMMENT 'Source system that triggered or originated the quarantine hold (e.g., LIMS = LabWare LIMS for OOS results; EHS = Intelex EHS for safety incidents; SAP_QM = SAP Quality Management for inspection lot failures; MES = Manufacturing Execution System; MANUAL = manually initiated by QA personnel). [ENUM-REF-CANDIDATE: LIMS|EHS|SAP_QM|MES|MANUAL|SCADA|ERP — 7 candidates stripped; promote to reference product]',
    `initiator_name` STRING COMMENT 'Full name of the person who initiated the quarantine hold. Retained for audit trail and regulatory reporting purposes where employee ID alone is insufficient.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or storage facility where the quarantined material is physically located (e.g., PLANT01, TX02).',
    `purchase_order_number` STRING COMMENT 'Purchase Order (PO) number associated with the quarantined material if it was received from an external supplier. Used for supplier quality management, return-to-supplier disposition, and debit memo processing.',
    `regulatory_hold_reference` STRING COMMENT 'External regulatory agency reference number or directive identifier when the hold is initiated by a regulatory body (e.g., EPA enforcement action number, OSHA citation reference, FDA warning letter number, ECHA restriction notice). Null for non-regulatory holds.',
    `storage_location` STRING COMMENT 'SAP storage location (LGORT) or warehouse bin where the quarantined material is physically held. Includes tank farm designations, warehouse zones, and quarantine bays.',
    `target_resolution_date` DATE COMMENT 'Target date by which the quarantine hold disposition must be resolved (released or rejected). Used for SLA tracking, escalation management, and inventory planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp when the quarantine hold record was last modified. Tracks changes to disposition, status, or hold details.',
    CONSTRAINT pk_quarantine_hold PRIMARY KEY(`quarantine_hold_id`)
) COMMENT 'Record of a quarantine or quality hold placed on a specific lot or stock quantity, preventing it from being issued or shipped until disposition is resolved. Captures hold reference number, material, lot, quantity affected, hold reason (OOS result, customer complaint, regulatory hold, damage), hold initiator, hold date, target resolution date, CAPA reference, and release or rejection outcome. Integrates with LabWare LIMS and Intelex EHS for hold initiation triggers.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`physical_inventory_count` (
    `physical_inventory_count_id` BIGINT COMMENT 'Unique surrogate identifier for each physical inventory count record in the lakehouse silver layer. Maps to SAP MM physical inventory document item.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Period-end close and financial reporting: physical inventory counts are scheduled and posted within specific fiscal periods. Linking to fiscal_period enables automated period-close validation, audit t',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: A physical inventory count is performed at the lot level in chemical manufacturing (FIFO/FEFO compliance requires lot-level counting). Adding lot_id FK to inventory.lot enables direct linkage between ',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: Physical inventory count should reference the stock position record that aggregates quantity and location; removes duplicated attributes.',
    `approval_notes` STRING COMMENT 'Free-text notes entered by the approver explaining the rationale for approving the variance write-off. Supports audit documentation and Root Cause Investigation (RCI) for recurring discrepancies.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the variance write-off was approved by the authorized approver. Part of the SOX-compliant approval chain audit trail for inventory reconciliation.',
    `book_quantity` DECIMAL(18,2) COMMENT 'System-recorded (book) quantity of the material at the storage location at the time the count document was created, as per SAP MM inventory records. Represents the expected quantity before physical verification.',
    `count_date` DATE COMMENT 'Calendar date on which the physical count was performed. Used for inventory valuation cutoff, regulatory reporting, and SOX period-end reconciliation.',
    `count_document_item` STRING COMMENT 'Line item number within the SAP physical inventory document, distinguishing individual material-storage location combinations within the same count document.',
    `count_document_number` STRING COMMENT 'SAP MM physical inventory document number (MI01/MI04) that uniquely identifies the count event in the source system. Used for reconciliation and audit trail back to SAP.',
    `count_method` STRING COMMENT 'Indicates whether the count was performed blind (counter not shown book quantity, reducing bias) or informed (counter shown book quantity). Blind counting is preferred for SOX-compliant inventory reconciliation.. Valid values are `blind|informed`',
    `count_status` STRING COMMENT 'Current lifecycle status of the count document: open (count not yet performed), counted (count entered, pending posting), recounted (recount completed), posted (variance posted to inventory), cancelled (count voided).. Valid values are `open|counted|recounted|posted|cancelled`',
    `count_timestamp` TIMESTAMP COMMENT 'Precise date and time when the physical count was recorded, including timezone offset. Used for intraday reconciliation and audit trail in continuous process manufacturing environments.',
    `count_type` STRING COMMENT 'Classification of the count event: cycle_count (periodic scheduled count of a subset of materials), annual_wall_to_wall (full facility count), triggered_count (initiated due to discrepancy or event), or recount (second count to resolve variance).. Valid values are `cycle_count|annual_wall_to_wall|triggered_count|recount`',
    `counted_quantity` DECIMAL(18,2) COMMENT 'Actual physical quantity of the material counted and recorded by the counter. This is the primary measurement outcome of the count event.',
    `counter_name` STRING COMMENT 'Full name of the employee who performed the physical count. Stored for audit readability and SOX compliance reporting without requiring a join to HR systems.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the physical inventory count record was first created in the source system (SAP MM). Used for audit trail, data lineage, and SOX record retention compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the inventory valuation amount (e.g., USD, EUR). Supports multi-currency operations across global chemical manufacturing sites.. Valid values are `^[A-Z]{3}$`',
    `expiration_date` DATE COMMENT 'Expiration or shelf-life expiry date of the lot/batch being counted. Critical for FEFO (First Expired First Out) lot rotation compliance and identification of expired stock during physical counts.',
    `fiscal_period` STRING COMMENT 'Accounting period (month) within the fiscal year during which the count was performed (e.g., 001 through 012). Used for period-end inventory cutoff and financial close processes.',
    `fiscal_year` STRING COMMENT 'Fiscal year in which the physical inventory count was performed. Used for period-end financial reporting, SOX compliance, and year-over-year inventory accuracy trend analysis.. Valid values are `^[0-9]{4}$`',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the material being counted is classified as hazardous under GHS, OSHA, or DOT regulations. Drives additional safety protocols during physical counting and storage compliance checks.',
    `inventory_valuation_amount` DECIMAL(18,2) COMMENT 'Monetary value of the inventory variance calculated as variance_quantity multiplied by the standard or moving average price of the material. Used for financial impact assessment and COGS adjustment. Expressed in local currency.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the physical inventory count record. Supports incremental data loading in the Databricks lakehouse silver layer and change data capture tracking.',
    `material_description` STRING COMMENT 'Short description of the material being counted as maintained in the SAP material master. Provides human-readable context for reporting without requiring a join to the material master.',
    `material_document_number` STRING COMMENT 'SAP material document number generated when the inventory variance is posted (Transaction MI07). Links this count record to the resulting inventory_adjustment material document for financial reconciliation.',
    `posting_date` DATE COMMENT 'Accounting date on which the inventory variance was posted to the general ledger in SAP FI/CO. Critical for period-end cutoff, COGS calculation, and SOX financial reporting compliance.',
    `posting_status` STRING COMMENT 'Status of the variance posting to the SAP general ledger: not_posted (pending), posted (successfully posted), posting_failed (error during posting), reversed (posting reversed for correction).. Valid values are `not_posted|posted|posting_failed|reversed`',
    `quarantine_status` STRING COMMENT 'Stock status of the material at time of count: unrestricted (available for use), quarantine (held pending investigation), blocked (restricted from use), quality_inspection (held for QC testing). Aligns with SAP MM stock categories.. Valid values are `unrestricted|quarantine|blocked|quality_inspection`',
    `recount_flag` BOOLEAN COMMENT 'Indicates whether a recount has been triggered for this count item, typically due to variance exceeding the tolerance threshold. True = recount required or performed; False = no recount needed.',
    `recount_number` STRING COMMENT 'Sequential number indicating which recount iteration this record represents (1 = first recount, 2 = second recount, etc.). Zero or null indicates the original count. Supports multi-round recount audit trails.',
    `special_stock_indicator` STRING COMMENT 'Indicates the ownership or allocation type of the stock being counted: own (company-owned), consignment (customer-owned at our facility), project (allocated to a project), sales_order (reserved for a sales order), vendor_consignment (vendor-owned at our facility).. Valid values are `own|consignment|project|sales_order|vendor_consignment`',
    `unit_of_measure` STRING COMMENT 'Unit of measure in which the book, counted, and variance quantities are expressed (e.g., KG, L, MT, EA, DR for drums). Aligns with SAP base unit of measure from the material master.',
    `variance_percentage` DECIMAL(18,2) COMMENT 'Variance quantity expressed as a percentage of book quantity. Used to determine whether variance exceeds tolerance thresholds requiring management approval or recount. Key KPI for inventory accuracy reporting.',
    `variance_quantity` DECIMAL(18,2) COMMENT 'Difference between counted quantity and book quantity (counted_quantity minus book_quantity). Positive value indicates surplus; negative value indicates shortage. Drives inventory adjustment postings.',
    `variance_tolerance_pct` DECIMAL(18,2) COMMENT 'Allowable variance percentage threshold configured for this material or material group. Variances exceeding this threshold require management approval for write-off. Supports SOX-compliant variance authorization controls.',
    `warehouse_number` STRING COMMENT 'SAP EWM warehouse number identifying the logical warehouse complex. Used when the count is managed at the warehouse management level rather than simple storage location level.',
    `within_tolerance_flag` BOOLEAN COMMENT 'Indicates whether the variance percentage is within the configured tolerance threshold. True = variance is acceptable and can be auto-posted; False = variance exceeds tolerance and requires manual approval.',
    CONSTRAINT pk_physical_inventory_count PRIMARY KEY(`physical_inventory_count_id`)
) COMMENT 'Record of a physical inventory count event (cycle count, annual wall-to-wall count, or triggered count) for a specific material at a specific storage location or bin. Captures count document number, count date, counter identity, book quantity at time of count, counted quantity, variance quantity, variance percentage, recount flag, count method (blind vs. informed), posting status, and approval chain for variance write-off. Supports regulatory and SOX-compliant inventory reconciliation and feeds inventory_adjustment records for variance postings. Integrates with SAP MM physical inventory module.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`hazmat_storage_rule` (
    `hazmat_storage_rule_id` BIGINT COMMENT 'Unique surrogate identifier for each hazardous material storage compatibility and segregation rule record. Primary key for the hazmat_storage_rule reference entity. [_canonical_skip_reason: Entity role classified as REFERENCE_LOOKUP — defines a codified regulatory/operational rule set governing chemical storage compatibility; no per-role minimum categories apply, but comprehensive coverage is still provided for enterprise utility.]',
    `cas_registry_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.cas_registry. Business justification: Hazmat storage rules in chemical manufacturing are authored for specific chemical substances identified by CAS number. Linking hazmat_storage_rule to cas_registry enables automated rule lookup during ',
    `approval_date` DATE COMMENT 'Date on which this storage rule was formally approved by the designated EHS authority. Part of the MOC documentation chain. Required for OSHA PSM compliance audits and ISO 9001 document control records.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the EHS Manager, Process Safety Engineer, or Regulatory Affairs Officer who formally approved this storage rule for operational use. Required for MOC (Management of Change) documentation and regulatory audit trails per OSHA PSM and ISO 45001.',
    `classification_system` STRING COMMENT 'Primary hazard classification system under which this storage rule is defined (e.g., GHS for global chemical classification, NFPA for US fire codes, UN for transport, IMDG for maritime, CLP for EU). Determines which regulatory framework governs the rules applicability. [ENUM-REF-CANDIDATE: GHS|NFPA|UN|DOT|IMDG|IATA|CLP|WHMIS — 8 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this hazmat storage rule record was first created in the system. Provides audit trail for rule origination. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX per enterprise data standards.',
    `effective_date` DATE COMMENT 'Date from which this storage rule version becomes enforceable in warehouse operations. Rules with a future effective date are loaded into SAP EWM in draft status and activated on the effective date. Supports regulatory transition periods.',
    `epa_regulatory_citation` STRING COMMENT 'Specific EPA regulatory citation (CFR part and section) that mandates or informs this storage rule (e.g., 40 CFR Part 112, 40 CFR Part 68 RMP, 40 CFR Part 264 Subpart I). Used in environmental compliance reporting and audit documentation submitted to EPA.',
    `expiry_date` DATE COMMENT 'Date on which this storage rule version expires or is superseded. Null indicates the rule is open-ended with no planned expiry. When populated, the system automatically transitions the rule to superseded status and activates the replacement rule version.',
    `fire_suppression_required` BOOLEAN COMMENT 'Indicates whether an automatic fire suppression system (sprinkler, deluge, foam, or dry chemical) is required at the storage location for chemicals governed by this rule. Drives facility engineering requirements and influences NFPA 400 maximum allowable quantity multipliers.',
    `fire_zone_type` STRING COMMENT 'Classification of the fire zone or control area type to which the maximum quantity limit applies. NFPA 400 and IFC allow higher MAQ in sprinklered buildings versus unprotected control areas. Drives differentiated quantity limits in SAP EWM storage type configuration.. Valid values are `control_area|sprinklered_building|detached_storage|outdoor_storage|tank_farm`',
    `ghs_hazard_statement_codes` STRING COMMENT 'Comma-separated list of GHS H-statement codes applicable to chemicals governed by this rule (e.g., H225,H302,H314). Drives SDS Section 2 alignment and label generation. Used in REACH and CLP regulatory reporting.. Valid values are `^H[0-9]{3}(,H[0-9]{3})*$`',
    `grounding_bonding_required` BOOLEAN COMMENT 'Indicates whether electrical grounding and bonding equipment is required at the storage location for chemicals governed by this rule. Mandatory for flammable liquids with flash points below 100°F to prevent static discharge ignition per NFPA 77 and OSHA standards.',
    `hazard_class` STRING COMMENT 'Primary GHS/UN hazard class of the chemical governed by this rule (e.g., Class 3 Flammable Liquids, Class 5.1 Oxidizing Substances, Class 8 Corrosives, Class 6.1 Toxic Substances). Aligns with UN Model Regulations and GHS classification. [ENUM-REF-CANDIDATE: Class 1|Class 2|Class 3|Class 4|Class 5.1|Class 5.2|Class 6.1|Class 6.2|Class 7|Class 8|Class 9 — promote to reference product]',
    `hazard_sub_risk` STRING COMMENT 'Secondary hazard classification or division providing additional specificity within the primary hazard class (e.g., Division 1.1 for mass explosion risk, Packing Group I/II/III, sub-risk 6.1 on a Class 3 flammable). Captures multi-hazard chemical profiles per GHS and UN regulations.',
    `incompatibility_consequence` STRING COMMENT 'Primary hazardous consequence that would result from co-locating the two incompatible hazard classes defined in this rule. Used in risk assessment, PHA/HAZOP documentation, and emergency response planning. Informs the severity weighting in automated putaway violation alerts.. Valid values are `fire|explosion|toxic_gas_release|violent_reaction|polymerization|corrosion`',
    `incompatible_hazard_class_a` STRING COMMENT 'First hazard class in the incompatible pair defined by this segregation rule. Together with incompatible_hazard_class_b, forms the segregation matrix entry that prohibits co-location of chemicals from these two hazard classes in the same storage zone. Aligns with NFPA 400 Table 10.3.2 and UN segregation table.',
    `incompatible_hazard_class_b` STRING COMMENT 'Second hazard class in the incompatible pair defined by this segregation rule. Together with incompatible_hazard_class_a, forms the segregation matrix entry. The automated putaway validation engine in SAP EWM checks both directions of this pair to prevent co-location of incompatible chemicals.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this hazmat storage rule record was last updated. Supports change detection in downstream ETL pipelines and provides audit trail for rule modifications. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX per enterprise data standards.',
    `last_reviewed_date` DATE COMMENT 'Date on which this storage rule was last reviewed for continued regulatory accuracy and operational relevance. ISO 14001 and ISO 45001 require periodic review of EHS controls. Triggers a review workflow in Intelex EHS Management when overdue.',
    `max_quantity_per_fire_zone_kg` DECIMAL(18,2) COMMENT 'Maximum allowable quantity in kilograms of chemicals governed by this rule that may be stored within a single fire zone or control area. Derived from NFPA 400 maximum allowable quantities (MAQ) tables and local fire code. Enforced by SAP EWM inventory capacity checks.',
    `max_quantity_per_fire_zone_l` DECIMAL(18,2) COMMENT 'Maximum allowable quantity in liters of liquid chemicals governed by this rule that may be stored within a single fire zone or control area. Complements the kilogram-based limit for liquid hazmat categories where volume is the regulatory basis (e.g., NFPA 30 flammable liquids).',
    `max_storage_temp_c` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature in degrees Celsius for chemicals governed by this rule. Exceeding this threshold may cause decomposition, polymerization, or ignition. Monitored via Aveva PI System historian and triggers automated EHS alerts in Intelex.',
    `min_storage_temp_c` DECIMAL(18,2) COMMENT 'Minimum allowable storage temperature in degrees Celsius for chemicals governed by this rule. Below this threshold, the chemical may solidify, become unstable, or lose efficacy. Monitored via Aveva PI System historian for real-time compliance alerting.',
    `next_review_date` DATE COMMENT 'Date by which this storage rule must next be reviewed for regulatory currency and operational accuracy. Calculated based on review frequency policy (typically annual for high-hazard rules). Drives compliance calendar in Intelex EHS Management.',
    `nfpa_flammability_rating` STRING COMMENT 'NFPA 704 fire diamond flammability rating (0–4) for chemicals governed by this rule. Rating 4 indicates materials that will rapidly vaporize at normal pressure and temperature. Used in fire zone maximum quantity calculations and emergency response planning.',
    `nfpa_health_rating` STRING COMMENT 'NFPA 704 fire diamond health hazard rating (0–4) for chemicals governed by this rule. Rating 4 indicates materials that can cause death or major residual injury on short exposure. Used in PPE requirements and emergency response planning.',
    `nfpa_reactivity_rating` STRING COMMENT 'NFPA 704 fire diamond instability/reactivity rating (0–4) for chemicals governed by this rule. Rating 4 indicates materials capable of detonation or explosive decomposition at normal temperatures and pressures.',
    `nfpa_special_hazard_code` STRING COMMENT 'NFPA 704 special hazard symbol code for chemicals governed by this rule (e.g., W = water-reactive, OX = oxidizer, SA = simple asphyxiant, BIO = biological hazard, CRY = cryogenic). Governs special storage precautions and emergency response procedures. [ENUM-REF-CANDIDATE: W|OX|SA|BIO|COR|POI|RAD|CRY|ACID|ALK — 10 candidates stripped; promote to reference product]',
    `osha_regulatory_citation` STRING COMMENT 'Specific OSHA regulatory citation (CFR part and section) that mandates or informs this storage rule (e.g., 29 CFR 1910.119 PSM, 29 CFR 1910.106 Flammable Liquids, 29 CFR 1910.1200 HazCom). Used in PSM compliance documentation and OSHA inspection readiness.',
    `packing_group` STRING COMMENT 'UN packing group designation (I = great danger, II = medium danger, III = minor danger) for the hazardous material governed by this rule. Determines packaging requirements for transport and influences storage quantity limits and segregation requirements.. Valid values are `I|II|III|N/A`',
    `reach_regulation_reference` STRING COMMENT 'REACH regulation article or annex reference applicable to this storage rule (e.g., REACH Annex XVII Restriction Entry 3, REACH Article 56 Authorization). Required for EU operations and ECHA compliance reporting. Populated for chemicals on the SVHC candidate list.',
    `rule_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this storage rule within the enterprise rule catalog (e.g., HSR-001, FLAM-OX-SEG-01). Used as the human-readable business key in SAP EWM putaway strategies and EHS management systems.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `rule_description` STRING COMMENT 'Full narrative description of the storage rule, including the rationale for the segregation or storage condition requirement, the chemical hazard interaction being prevented, and any operational guidance for warehouse personnel.',
    `rule_name` STRING COMMENT 'Descriptive short name for the storage rule (e.g., Flammable-Oxidizer Segregation, Corrosive-Reactive Incompatibility). Used in warehouse management UI labels and EHS compliance reports.',
    `rule_status` STRING COMMENT 'Current lifecycle status of the storage rule record. active rules are enforced in automated putaway validation. superseded rules have been replaced by a newer version. under_review rules are pending regulatory or internal re-assessment.. Valid values are `active|inactive|draft|superseded|under_review`',
    `rule_version` STRING COMMENT 'Version identifier for this storage rule record (e.g., v1.0, v2.3). Supports rule versioning when regulatory updates require rule revisions. Enables audit trail of rule changes over time and ensures warehouse systems reference the current approved version.. Valid values are `^v[0-9]+.[0-9]+$`',
    `sds_section_references` STRING COMMENT 'Comma-separated list of SDS section numbers that provide the source data for this storage rule (e.g., 7,8,10,14). Section 7 = Handling and Storage, Section 8 = Exposure Controls, Section 10 = Reactivity, Section 14 = Transport. Enables traceability from rule to SDS source documentation per GHS.',
    `segregation_distance_m` DECIMAL(18,2) COMMENT 'Minimum physical separation distance in meters required between storage locations holding chemicals from the two incompatible hazard classes defined in this rule. Used by SAP EWM bin assignment logic to enforce spatial separation within the warehouse or tank farm.',
    `storage_location_type` STRING COMMENT 'Type of physical storage location required for chemicals governed by this rule. Drives SAP EWM storage type determination during putaway. tank_farm applies to bulk liquid chemicals. refrigerated_room applies to temperature-sensitive hazmat. Validated against warehouse master data.. Valid values are `indoor_cabinet|indoor_room|outdoor_yard|tank_farm|underground_tank|refrigerated_room`',
    `un_number` STRING COMMENT 'UN four-digit identification number for the hazardous substance or article governed by this rule (e.g., UN1203 for gasoline, UN1824 for sodium hydroxide solution). Used in DOT transport documentation, emergency response, and cross-referencing with the UN Model Regulations segregation table.. Valid values are `^UN[0-9]{4}$`',
    `ventilation_class` STRING COMMENT 'Required ventilation classification for storage areas holding chemicals governed by this rule. local_exhaust indicates dedicated fume extraction is required. explosion_proof indicates ATEX/NEC-rated ventilation systems are mandatory. Aligns with OSHA industrial hygiene requirements and NFPA 30.. Valid values are `general|local_exhaust|explosion_proof|none_required|specialized`',
    CONSTRAINT pk_hazmat_storage_rule PRIMARY KEY(`hazmat_storage_rule_id`)
) COMMENT 'Reference record defining hazardous material storage compatibility and segregation rules per GHS, NFPA, and UN hazard classification systems. Captures hazard class, sub-risk, NFPA fire diamond rating, incompatible hazard class pairs (segregation matrix), required storage conditions (temperature range, ventilation class, secondary containment type), maximum storage quantity per fire zone, EPA/OSHA regulatory citation, and applicable SDS section references. Governs automated putaway validation ensuring incompatible chemicals are never co-located in the same storage zone.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`storage_bin` (
    `storage_bin_id` BIGINT COMMENT 'Unique surrogate identifier for the storage bin master record in the SAP Extended Warehouse Management (EWM) system. Serves as the primary key for all bin-level inventory tracking and directed putaway/picking operations.',
    `hazmat_storage_rule_id` BIGINT COMMENT 'Foreign key linking to inventory.hazmat_storage_rule. Business justification: Hazardous storage rules are defined centrally; link bin to rule and remove duplicated class info.',
    `warehouse_location_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse_location. Business justification: Storage bin belongs to a warehouse location; replace free‑text warehouse_number with FK for proper hierarchy.',
    `aisle` STRING COMMENT 'Aisle identifier within the warehouse where the storage bin is physically located. Used for warehouse navigation, slotting optimization, and pick path sequencing.. Valid values are `^[A-Z0-9]{1,5}$`',
    `allowed_material_types` STRING COMMENT 'Comma-separated list of SAP material type codes (e.g., ROH for raw materials, FERT for finished goods, HALB for semi-finished, VERP for packaging) permitted to be stored in this bin. Enforces material segregation rules for chemical compatibility and regulatory compliance.',
    `bin_access_type` STRING COMMENT 'Type of material handling equipment required to access this storage bin. Determines equipment assignment during transfer order creation and supports warehouse resource planning. Critical for safety compliance in chemical warehouses where certain hazmat bins require specialized handling equipment.. Valid values are `forklift|reach_truck|manual|automated|crane`',
    `bin_code` STRING COMMENT 'Alphanumeric code that uniquely identifies the physical storage bin within a warehouse number and storage type. Corresponds to the SAP EWM Lgpla field. Used in directed putaway, picking, and bin-level inventory queries.. Valid values are `^[A-Z0-9-]{1,18}$`',
    `bin_description` STRING COMMENT 'Free-text description of the storage bin providing additional context about its physical characteristics, special use restrictions, or operational notes. May include information about dedicated chemical families, special handling requirements, or historical usage notes.',
    `bin_name` STRING COMMENT 'Human-readable descriptive name or label for the storage bin, used in warehouse operations, signage, and reporting. May include aisle, row, and level descriptors (e.g., Aisle-A Row-03 Level-02) to aid physical navigation.',
    `bin_status` STRING COMMENT 'Current operational lifecycle status of the storage bin. Active bins are available for putaway and picking. Blocked bins are temporarily unavailable. Quarantine status is applied when contents are under quality hold per QM procedures. Maintenance status indicates the bin is undergoing physical inspection or repair.. Valid values are `active|inactive|blocked|quarantine|maintenance`',
    `bin_type` STRING COMMENT 'Classification of the physical bin configuration. Fixed bins are dedicated to specific materials (e.g., hazardous chemicals); random bins accept any compatible material; bulk bins hold large quantities; tank bins represent liquid storage vessels in tank farms; floor bins are ground-level pallet positions; rack bins are elevated rack locations.. Valid values are `fixed|random|bulk|tank|floor|rack`',
    `containment_type` STRING COMMENT 'Type of secondary containment infrastructure present at this storage bin to prevent chemical spills from reaching drains or the environment. Secondary bund and tank bund are used for bulk liquid chemical storage; spill pallets for drum storage; lined floor for general chemical areas. Required for EPA SPCC compliance and ISO 14001 environmental management.. Valid values are `none|secondary_bund|spill_pallet|lined_floor|tank_bund`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the storage bin master record was first created in the system. Provides audit trail for bin lifecycle management and supports data governance requirements.',
    `current_quantity` DECIMAL(18,2) COMMENT 'Current number of handling units (pallets, drums, IBCs) physically present in the bin. Reflects the real-time stock count as maintained by SAP EWM goods movements.',
    `current_volume_m3` DECIMAL(18,2) COMMENT 'Current total volume in cubic meters occupied by stock in the bin. Compared against max_volume_m3 to determine available capacity for putaway decisions.',
    `current_weight_kg` DECIMAL(18,2) COMMENT 'Current total gross weight in kilograms of all stock currently stored in the bin. Updated upon each goods movement. Used to monitor bin load against maximum weight capacity and support structural safety compliance.',
    `deactivation_date` DATE COMMENT 'Date on which the storage bin was or is scheduled to be deactivated and removed from active warehouse operations. Null for currently active bins. Supports bin lifecycle management and warehouse restructuring projects.',
    `fire_protection_zone` STRING COMMENT 'NFPA fire protection zone or compartment designation assigned to the storage bin. Used to enforce fire load limits, sprinkler system coverage mapping, and emergency response planning for flammable and combustible chemical storage areas.',
    `is_fixed_bin` BOOLEAN COMMENT 'Indicates whether this bin is a fixed bin permanently assigned to a specific material or material group, as opposed to a random bin available for any compatible material. True = fixed bin assignment; False = random bin. Drives SAP EWM putaway strategy determination.',
    `is_hazmat_approved` BOOLEAN COMMENT 'Indicates whether this storage bin has been formally approved and certified for the storage of hazardous materials in compliance with OSHA PSM, EPA RMP, and GHS regulations. True = approved for hazmat storage; False = not approved.',
    `is_quarantine_bin` BOOLEAN COMMENT 'Indicates whether this bin is designated as a quarantine storage location for materials under quality hold, out-of-specification (OOS) status, or pending Certificate of Analysis (COA) release. True = quarantine bin; False = standard bin. Integrates with SAP QM quality inspection workflows.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent physical safety or structural inspection of the storage bin, including rack integrity checks, containment integrity, and hazmat compliance verification. Supports OSHA PSM and ISO 45001 occupational health and safety compliance.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the storage bin master record. Used for change tracking, data lineage, and audit trail purposes in compliance with ISO 9001 document control requirements.',
    `last_physical_inventory_date` DATE COMMENT 'Date on which the most recent physical inventory count or cycle count was performed for this storage bin. Used to track inventory accuracy compliance, schedule future counts, and support SOX financial reporting requirements for inventory valuation.',
    `max_quantity` DECIMAL(18,2) COMMENT 'Maximum number of handling units (pallets, drums, IBCs, or containers) that can be stored in the bin simultaneously. Enforced during directed putaway to prevent overfilling.',
    `max_stacking_height_m` DECIMAL(18,2) COMMENT 'Maximum allowable stacking height in meters for materials stored in this bin. Enforced to prevent structural overload and comply with OSHA stacking safety regulations. Particularly relevant for drum and IBC storage of liquid chemicals.',
    `max_temperature_c` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature in degrees Celsius for this bin. Prevents thermal degradation, polymerization, or hazardous decomposition of stored chemicals. Critical for compliance with SDS storage requirements.',
    `max_volume_m3` DECIMAL(18,2) COMMENT 'Maximum storage volume in cubic meters available within the bin. Used for volumetric capacity planning, putaway feasibility checks, and tank farm liquid volume management.',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum allowable gross weight in kilograms that the storage bin can safely hold, including packaging and handling units. Critical for structural safety compliance and overload prevention in chemical warehouses storing dense raw materials or bulk liquids.',
    `min_temperature_c` DECIMAL(18,2) COMMENT 'Minimum allowable storage temperature in degrees Celsius for this bin. Enforced for temperature-sensitive chemical raw materials, intermediates, and finished goods to prevent degradation, crystallization, or phase separation.',
    `next_inspection_due_date` DATE COMMENT 'Scheduled date for the next mandatory safety or structural inspection of the storage bin. Drives preventive maintenance scheduling and ensures continuous compliance with OSHA, NFPA, and ISO 45001 inspection frequency requirements.',
    `occupancy_status` STRING COMMENT 'Real-time occupancy state of the storage bin indicating whether the bin is empty, fully occupied, partially occupied, or reserved for an incoming transfer order. Drives directed putaway logic in SAP EWM and supports inventory accuracy reporting.. Valid values are `empty|occupied|partially_occupied|reserved`',
    `picking_point` STRING COMMENT 'SAP EWM picking point bin code associated with this storage bin. For bulk or reserve storage bins, identifies the forward pick face bin from which order picking is executed. Supports two-step picking workflows common in chemical distribution operations.. Valid values are `^[A-Z0-9-]{1,18}$`',
    `putaway_strategy` STRING COMMENT 'SAP EWM putaway strategy assigned to this bin that determines how incoming stock is directed to storage locations. Fixed strategy assigns stock to pre-defined bins; open storage allows any compatible bin; bulk strategy consolidates large quantities; near-picking places fast-movers close to pick areas; addition-to-existing consolidates partial bins.. Valid values are `fixed|open_storage|bulk|near_picking|addition_to_existing`',
    `rotation_strategy` STRING COMMENT 'Inventory lot rotation strategy applied to this bin for picking sequence determination. FIFO (First In First Out) is standard for most chemicals; FEFO (First Expired First Out) is mandatory for materials with expiration dates to prevent use of expired lots; LIFO and LEFO are used in specific bulk storage scenarios. Aligns with GMP and ISO 9001 inventory management requirements.. Valid values are `FIFO|FEFO|LIFO|LEFO|manual`',
    `row_number` STRING COMMENT 'Row number within the aisle that identifies the horizontal position of the storage bin. Combined with aisle and level, provides the full physical coordinate of the bin within the warehouse.. Valid values are `^[0-9]{1,4}$`',
    `storage_bin_level` STRING COMMENT 'Vertical level or tier of the storage bin within a rack structure. Level 1 is ground floor; higher numbers indicate elevated rack positions. Used for equipment assignment (e.g., forklift vs. reach truck) and weight distribution planning.. Valid values are `^[0-9]{1,3}$`',
    `storage_section_code` STRING COMMENT 'SAP EWM storage section (Lgber) code that subdivides a storage type into logical groupings, such as fast-moving, slow-moving, or temperature-controlled sections. Used to optimize putaway strategies for chemical raw materials and finished goods.. Valid values are `^[A-Z0-9]{1,3}$`',
    `storage_type_code` STRING COMMENT 'SAP EWM storage type (Lgtyp) code that classifies the physical area of the warehouse where this bin resides, such as high-rack storage, bulk storage, tank farm, or hazardous material area. Drives putaway and picking strategies.. Valid values are `^[A-Z0-9]{3}$`',
    `temperature_zone` STRING COMMENT 'Temperature-controlled storage zone classification for the bin. Ambient bins operate at room temperature; refrigerated bins maintain 2–8°C for temperature-sensitive chemicals or intermediates; heated bins prevent solidification of high-melting-point materials; controlled bins maintain a specific validated temperature range per product specification.. Valid values are `ambient|refrigerated|frozen|heated|controlled`',
    `ventilation_required` BOOLEAN COMMENT 'Indicates whether this storage bin requires dedicated ventilation or is located in a ventilated area to manage volatile organic compound (VOC) emissions or hazardous air pollutant (HAP) concentrations. True = ventilation required; False = no special ventilation needed. Supports EHS compliance with EPA and OSHA air quality standards.',
    CONSTRAINT pk_storage_bin PRIMARY KEY(`storage_bin_id`)
) COMMENT 'Master record for individual storage bins within a warehouse location, representing the smallest addressable unit of storage in SAP EWM. Captures bin code, warehouse number, storage type, storage section, bin capacity (weight and volume), bin type (fixed, random, bulk, tank), current occupancy status, maximum weight, and allowed material types. Enables precise bin-level inventory tracking and directed putaway/picking strategies.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`stock_reservation` (
    `stock_reservation_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the stock reservation record in the inventory management system.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Supports Customer Allocation Report by linking each inventory reservation to the customer account that requested the reservation, enabling order fulfillment tracking.',
    `customer_allocation_id` BIGINT COMMENT 'Foreign key linking to planning.customer_allocation. Business justification: In chemical manufacturing supply constraints, customer allocations authorize specific reservation quantities per customer. Stock reservations must reference the customer allocation that authorized the',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Project budget consumption monitoring: stock reservations for maintenance shutdowns, R&D, or capital projects are created against internal orders. Linking enables real-time budget consumption tracking',
    `line_item_id` BIGINT COMMENT 'Foreign key linking to product.line_item. Business justification: In chemical manufacturing, stock reservations are created at sales order line item level for lot-controlled and hazmat materials (SAP MRP reservation process). Linking reservation to line_item enables',
    `lot_id` BIGINT COMMENT 'Reference to the specific inventory lot or batch being earmarked. Supports FIFO/FEFO lot rotation and prevents double-allocation of expiring chemical stock.',
    `manufacturing_order_id` BIGINT COMMENT 'Foreign key linking to production.manufacturing_order. Business justification: Stock reservations are fundamentally created against manufacturing orders in chemical plant MRP/ERP systems (SAP movement type 261). Direct FK enables manufacturing order material availability confirm',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the chemical, raw material, intermediate, finished good, or packaging material being reserved.',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Needed for allocation reports: reserving stock for a specific sales opportunity ensures availability and supports the Opportunity‑to‑Inventory allocation process.',
    `order_id` BIGINT COMMENT 'Reference to the production order, customer delivery order, or maintenance work order that will consume the reserved stock. Establishes the demand source driving the reservation.',
    `price_agreement_id` BIGINT COMMENT 'Foreign key linking to sales.price_agreement. Business justification: Contract-priced reservation valuation: in chemical manufacturing, stock reserved for contract customers must be valued and allocated under the governing price agreement. This link enables accurate res',
    `process_order_id` BIGINT COMMENT 'Foreign key linking to production.process_order. Business justification: Stock reservations in chemical manufacturing are created against process orders to ensure material availability before production starts. Direct FK enables material availability checks and reservation',
    `quality_specification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_specification. Business justification: Stock reservations for chemical products must specify the required quality specification (grade, purity, regulatory compliance). In chemical manufacturing, customers order to specific quality specs; r',
    `quote_id` BIGINT COMMENT 'Foreign key linking to sales.quote. Business justification: Quote-driven inventory reservation: when a customer accepts a quote, chemical manufacturers reserve stock against that quote prior to order conversion. This link enables quote-to-reservation traceabil',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: A stock reservation earmarks a specific quantity from a specific stock position. Adding stock_position_id FK to inventory.stock_position enables direct linkage between reservations and the position be',
    `warehouse_location_id` BIGINT COMMENT 'Reference to the warehouse location or tank farm where the reserved stock is physically stored.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Reservation of inventory for a specific maintenance work order; needed for parts reservation and work order cost tracking.',
    `auto_release_flag` BOOLEAN COMMENT 'Indicates whether the reservation should be automatically released back to available stock upon reaching the expiry date without fulfillment. Supports automated inventory management and prevents indefinite stock lock-up.',
    `coa_required` BOOLEAN COMMENT 'Indicates whether a Certificate of Analysis must be verified and attached before the reserved stock can be issued to the consuming order. Enforces quality gate compliance for regulated chemical products.',
    `consuming_order_type` STRING COMMENT 'Specifies the type of the consuming order document. Distinguishes between production orders, process orders (for batch chemical manufacturing), sales delivery orders, maintenance orders, and project orders to support domain-specific analytics.. Valid values are `production_order|process_order|sales_delivery|maintenance_order|project_order`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the stock reservation record was first created in the system. Used for audit trail, SLA tracking, and data lineage.',
    `expiry_date` DATE COMMENT 'The date after which the reservation is no longer valid and the earmarked stock is automatically released back to available inventory. Critical for preventing indefinite stock lock-up of expiring chemical materials.',
    `fulfilled_quantity` DECIMAL(18,2) COMMENT 'Cumulative quantity of the reservation that has already been issued or withdrawn against the consuming order. Used to calculate the remaining open quantity and determine partial fulfillment status.',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether the reserved material is classified as hazardous. When true, additional handling, storage compliance, and transport regulations apply per OSHA, DOT, and REACH requirements.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when the stock reservation record was most recently modified, such as a quantity change, status update, or date revision. Supports change tracking and data reconciliation.',
    `material_number` STRING COMMENT 'The ERP material number (SAP material number) of the chemical or material being reserved. Serves as the externally-known business identifier for cross-system reference and reporting.',
    `movement_type_code` STRING COMMENT 'SAP goods movement type code that will be used when the reservation is fulfilled (e.g., 261 for goods issue to production order, 601 for goods issue to customer delivery). Determines the accounting and inventory impact of the eventual withdrawal.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special handling instructions, or comments entered by the planner or warehouse operator at the time of reservation creation or update.',
    `oos_flag` BOOLEAN COMMENT 'Indicates whether the reserved lot has been flagged as Out of Specification (OOS) by the quality management system. An OOS reservation is blocked from fulfillment pending CAPA resolution.',
    `partial_fulfillment_allowed` BOOLEAN COMMENT 'Indicates whether the consuming order can accept a partial goods issue against this reservation, or whether the full reserved quantity must be issued in a single transaction. Relevant for batch chemical processes with minimum charge quantities.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or distribution center where the reserved stock is located and where the consuming event will occur. Aligns with SAP organizational structure.',
    `priority` STRING COMMENT 'Numeric priority ranking of the reservation used to resolve allocation conflicts when available stock is insufficient to fulfill all open reservations. Lower values indicate higher priority (e.g., 1 = highest priority).',
    `quarantine_flag` BOOLEAN COMMENT 'Indicates whether the reserved lot is currently under quarantine hold (e.g., pending quality release, Out of Specification investigation, or regulatory hold). A quarantined reservation cannot be fulfilled until the hold is lifted.',
    `reach_compliant` BOOLEAN COMMENT 'Indicates whether the reserved material lot has been verified as compliant with REACH regulation requirements at the time of reservation. Prevents issuance of non-compliant chemical stock to production.',
    `requirement_date` DATE COMMENT 'The date on which the reserved material is required for consumption by the planned event (production start date, delivery date, or maintenance execution date). Drives FEFO/FIFO lot selection and warehouse picking scheduling.',
    `reservation_date` DATE COMMENT 'The business date on which the stock reservation was created and the stock was earmarked. Represents the principal real-world event time for the reservation transaction.',
    `reservation_number` STRING COMMENT 'Externally-known alphanumeric reservation document number assigned by the ERP or WMS system (e.g., SAP reservation number). Used for cross-system reference and communication with warehouse operations.',
    `reservation_reason_code` STRING COMMENT 'Business reason code explaining why the reservation was created (e.g., scheduled production run, emergency maintenance, customer priority order, safety stock replenishment). Supports demand analysis and inventory planning. [ENUM-REF-CANDIDATE: scheduled_production|emergency_maintenance|customer_priority|safety_stock|quality_sample|r_and_d_trial|regulatory_hold — promote to reference product]',
    `reservation_status` STRING COMMENT 'Current lifecycle state of the stock reservation. open indicates no goods movement has occurred; partially_fulfilled indicates some quantity has been issued; fulfilled indicates full quantity has been issued; cancelled indicates the reservation was voided before consumption.. Valid values are `open|partially_fulfilled|fulfilled|cancelled`',
    `reservation_type` STRING COMMENT 'Classification of the demand event driving the reservation. Distinguishes between production order consumption, customer delivery fulfillment, maintenance work order material staging, project-based withdrawal, or manually created reservations.. Valid values are `production_order|customer_delivery|maintenance_work_order|project|manual`',
    `reserved_quantity` DECIMAL(18,2) COMMENT 'Total quantity of the material and lot earmarked for the planned consumption event, expressed in the base unit of measure. Prevents double-allocation of limited or expiring chemical stock.',
    `sds_verified` BOOLEAN COMMENT 'Indicates whether the current Safety Data Sheet (SDS) for the reserved material has been verified as up-to-date and accessible prior to reservation fulfillment. Required for hazardous chemical handling compliance.',
    `source_system` STRING COMMENT 'Identifies the operational system of record that originated the reservation document (e.g., SAP EWM, SAP MM, SAP PP, SAP SD, SAP PM, or manually created). Supports data lineage and reconciliation in the lakehouse.. Valid values are `SAP_EWM|SAP_MM|SAP_PP|SAP_SD|SAP_PM|MANUAL`',
    `special_stock_indicator` STRING COMMENT 'Indicates the stock category from which the reservation will be fulfilled. Distinguishes between unrestricted-use stock, quality inspection stock, blocked stock, restricted-use stock, consignment stock, or project stock. Critical for chemical inventory where quarantine and quality holds are common.. Valid values are `unrestricted|quality_inspection|blocked|restricted|consignment|project`',
    `storage_location_code` STRING COMMENT 'SAP storage location code within the plant identifying the specific physical area (e.g., raw material warehouse, tank farm, hazmat storage, quarantine area) where the reserved stock is held.',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the reserved and fulfilled quantities (e.g., KG, L, MT, EA, BAG, DRUM). Aligns with the material master unit of measure in SAP MM.',
    `valuation_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the valuation price is expressed (e.g., USD, EUR). Required for multi-currency inventory valuation in global chemical manufacturing operations.. Valid values are `^[A-Z]{3}$`',
    `valuation_price` DECIMAL(18,2) COMMENT 'The standard or moving average price per unit of measure used to value the reserved stock at the time of reservation creation. Used for inventory valuation reporting and COGS calculation in SAP FI/CO.',
    CONSTRAINT pk_stock_reservation PRIMARY KEY(`stock_reservation_id`)
) COMMENT 'Record of a stock reservation that earmarks a specific quantity of a material and lot for a future planned consumption event such as a production order, customer delivery, or maintenance work order. Captures reservation number, material, lot, reserved quantity, unit of measure, requirement date, consuming order or delivery reference, reservation status (open, partially fulfilled, fulfilled, cancelled), and expiry date. Prevents double-allocation of limited or expiring chemical stock.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`tank_farm_level` (
    `tank_farm_level_id` BIGINT COMMENT 'Unique surrogate identifier for each tank farm level measurement record in the Silver Layer lakehouse. Primary key for this entity.',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Tank farm level readings track bulk liquid chemical inventory by product — essential for reorder point management, EPA/OSHA regulatory reporting, and REACH tonnage band compliance. Domain experts univ',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to maintenance.equipment. Business justification: Link tank level measurements to the tank equipment record for maintenance monitoring and regulatory compliance reporting.',
    `notification_id` BIGINT COMMENT 'Foreign key linking to maintenance.notification. Business justification: Tank level alarm breaches (high/low level alarms) in chemical plants automatically generate maintenance notifications in the CMMS via DCS/historian integration. Linking tank_farm_level readings to the',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record identifying the bulk liquid chemical currently stored in the tank at the time of measurement.',
    `production_plant_id` BIGINT COMMENT 'Reference to the manufacturing plant or site where the tank farm is located. Supports multi-site inventory tracking.',
    `quality_specification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_specification. Business justification: Bulk chemical tank farm levels must be monitored against quality specifications (purity, concentration, pH limits). In chemical manufacturing, continuous quality monitoring of bulk storage is required',
    `standard_cost_id` BIGINT COMMENT 'Foreign key linking to finance.standard_cost. Business justification: Bulk liquid inventory valuation: tank farm inventory_value_usd must be computed from standard cost records for balance sheet reporting. Chemical manufacturing domain experts expect tank farm contents ',
    `supply_plan_id` BIGINT COMMENT 'Foreign key linking to planning.supply_plan. Business justification: Tank farm levels for bulk liquid chemicals (solvents, acids, monomers) are the primary operational signal for supply plan execution. Planners monitor tank levels against supply plan replenishment trig',
    `tank_id` BIGINT COMMENT 'Reference to the storage tank asset record that this level measurement belongs to. Links to the tank master data entity in the inventory or asset domain.',
    `below_reorder_point_flag` BOOLEAN COMMENT 'Indicates whether the current tank inventory mass is at or below the defined reorder point threshold (True = replenishment required, False = adequate stock). Enables real-time inventory replenishment alerting and integration with SAP MM MRP processes.',
    `cas_number` STRING COMMENT 'The Chemical Abstracts Service (CAS) registry number uniquely identifying the chemical substance stored in the tank. Critical for regulatory reporting (TSCA, REACH, TRI), SDS linkage, and hazardous material compliance tracking.. Valid values are `^[0-9]{2,7}-[0-9]{2}-[0-9]$`',
    `data_collection_method` STRING COMMENT 'Describes how this measurement record was collected: automatic (real-time instrument feed via PI historian), manual (operator-entered gauge reading), or interpolated (value estimated between two valid readings). Supports data quality governance and audit trail requirements.. Valid values are `automatic|manual|interpolated`',
    `density_kg_m3` DECIMAL(18,2) COMMENT 'The density of the stored liquid at the measurement temperature, expressed in kilograms per cubic meter (kg/m³). Used to convert volume measurements to mass for inventory valuation and material balance. May be measured in-line or derived from temperature-corrected reference data.',
    `ghs_hazard_category` STRING COMMENT 'The GHS hazard category code for the stored chemical (e.g., Flammable Liquid Cat 1, Acute Toxicity Cat 3). Supports SDS compliance, emergency response documentation, and regulatory reporting under REACH, TSCA, and EPA requirements.',
    `hazmat_storage_class` STRING COMMENT 'The hazardous material storage class designation for the chemical stored in the tank, based on GHS/DOT classification (e.g., Class 3 Flammable Liquid, Class 8 Corrosive). Used for EHS compliance, emergency response planning, and segregation requirement enforcement. [ENUM-REF-CANDIDATE: class_1_explosive|class_2_gas|class_3_flammable_liquid|class_4_flammable_solid|class_5_oxidizer|class_6_toxic|class_7_radioactive|class_8_corrosive|class_9_misc — promote to reference product]',
    `high_level_alarm` BOOLEAN COMMENT 'Indicates whether the high-level alarm setpoint was active (True) or inactive (False) at the time of measurement. A high-level alarm signals that the tank level has reached or exceeded the high alarm threshold, requiring immediate operational attention to prevent overfill.',
    `instrument_tag` STRING COMMENT 'The P&ID instrument tag identifier for the level transmitter or gauge device that produced this measurement (e.g., LT-101, LIT-2204). Enables traceability to the physical instrument for calibration records, maintenance history, and instrument reliability analysis.',
    `inventory_value_usd` DECIMAL(18,2) COMMENT 'The estimated financial value of the bulk chemical inventory in the tank at the time of measurement, expressed in US Dollars. Calculated from mass_kg and the current standard or moving average cost from SAP FI/CO. Used for inventory valuation reporting and financial close processes.',
    `level_m` DECIMAL(18,2) COMMENT 'The measured liquid level height in the tank expressed in meters, as reported by the level transmitter instrument and captured in the Aveva PI System historian. This is the primary raw measurement value for continuous inventory tracking.',
    `level_percent` DECIMAL(18,2) COMMENT 'The current tank fill level expressed as a percentage of the tanks maximum working capacity (0-100%). Provides an intuitive operational view of tank utilization for dashboards, alerts, and capacity planning without requiring knowledge of tank dimensions.',
    `low_level_alarm` BOOLEAN COMMENT 'Indicates whether the low-level alarm setpoint was active (True) or inactive (False) at the time of measurement. A low-level alarm signals that the tank level has dropped to or below the low alarm threshold, indicating potential supply shortage or pump cavitation risk.',
    `mass_kg` DECIMAL(18,2) COMMENT 'The calculated mass of the liquid inventory in the tank expressed in kilograms, derived from volume and density. Used for material balance, production accounting, and regulatory emission calculations (e.g., EPA TRI, VOC reporting).',
    `measurement_quality` STRING COMMENT 'The data quality indicator for this measurement record as reported by the Aveva PI System historian (e.g., Good, Bad, Uncertain, Substituted). Reflects instrument health, communication status, or manual data substitution. Used to filter unreliable readings in analytics and reporting.. Valid values are `good|bad|uncertain|substituted`',
    `measurement_source` STRING COMMENT 'Identifies the originating source system or method for this level measurement record. Distinguishes between automated PI historian readings, manual gauge readings entered by operators, DCS/SCADA system feeds, calculated values from strapping tables, or estimated values.. Valid values are `pi_historian|manual_gauge|dcs_scada|calculated|estimated`',
    `measurement_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the tank level measurement was recorded by the process historian or instrumentation system. This is the principal real-world event time for this observation record.',
    `pi_tag_name` STRING COMMENT 'The Aveva PI System historian tag identifier (e.g., SITE01.TK-101.LEVEL) that is the source of this measurement record. Enables traceability back to the originating instrument data stream in the process historian.',
    `record_created_timestamp` TIMESTAMP COMMENT 'The date and time when this tank farm level record was first created or ingested into the Silver Layer data lakehouse. Distinct from measurement_timestamp (the real-world event time). Used for data pipeline auditing, latency monitoring, and record lineage tracking.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this tank farm level record was last modified in the Silver Layer, for example due to a data quality correction, manual override, or reprocessing event. Supports change tracking and data lineage auditing.',
    `reorder_point_kg` DECIMAL(18,2) COMMENT 'The inventory mass threshold in kilograms at which a replenishment order should be triggered for this tank. When mass_kg falls at or below this value, procurement or supply chain teams are alerted to initiate a purchase order or transfer. Supports continuous inventory management for bulk chemicals.',
    `storage_temperature_max_c` DECIMAL(18,2) COMMENT 'The maximum allowable storage temperature for the chemical in this tank, expressed in degrees Celsius, as specified in the material SDS (Safety Data Sheet). Exceeding this threshold may indicate a safety hazard, product degradation risk, or regulatory non-compliance.',
    `storage_temperature_min_c` DECIMAL(18,2) COMMENT 'The minimum allowable storage temperature for the chemical in this tank, expressed in degrees Celsius, as specified in the material SDS (Safety Data Sheet). Used to trigger temperature deviation alerts and ensure regulatory compliance with safe storage requirements.',
    `tank_capacity_m3` DECIMAL(18,2) COMMENT 'The nominal or maximum working capacity of the tank in cubic meters as defined in the tank design specification and strapping table. Stored with the measurement record to enable percentage calculations and capacity utilization reporting without requiring a join to the tank master.',
    `tank_farm_name` STRING COMMENT 'The name or designation of the tank farm area or storage cluster where the tank is physically located (e.g., North Tank Farm, Solvent Storage Area). Supports area-level inventory aggregation and reporting.',
    `temperature_c` DECIMAL(18,2) COMMENT 'The temperature of the liquid in the tank at the time of measurement, expressed in degrees Celsius. Temperature is required for density correction, volume-to-mass conversion, and monitoring of temperature-sensitive chemicals to ensure safe storage conditions.',
    `temperature_deviation_flag` BOOLEAN COMMENT 'Indicates whether the measured temperature at the time of this record was outside the defined safe storage temperature range (True = deviation detected, False = within range). Supports EHS compliance monitoring and automated alerting for temperature-sensitive chemical storage.',
    `ullage_m` DECIMAL(18,2) COMMENT 'The available headspace (ullage) in the tank expressed in meters, calculated as the difference between the maximum allowable working level and the current measured level. Critical for safe filling operations, overfill prevention, and scheduling inbound deliveries.',
    `ullage_volume_m3` DECIMAL(18,2) COMMENT 'The available headspace volume in the tank expressed in cubic meters, representing the remaining capacity available for additional material. Used for logistics planning, delivery scheduling, and overfill risk management.',
    `valuation_currency` STRING COMMENT 'The ISO 4217 three-letter currency code in which the inventory value is expressed (e.g., USD, EUR). Supports multi-currency reporting for global operations.. Valid values are `^[A-Z]{3}$`',
    `volume_liters` DECIMAL(18,2) COMMENT 'The calculated volume of liquid in the tank expressed in liters, derived from the level measurement and tank strapping table. Used for inventory quantity reporting and material balance calculations.',
    `volume_m3` DECIMAL(18,2) COMMENT 'The calculated volume of liquid in the tank expressed in cubic meters (m³). Provides SI unit representation for regulatory reporting, engineering calculations, and international trade documentation.',
    CONSTRAINT pk_tank_farm_level PRIMARY KEY(`tank_farm_level_id`)
) COMMENT 'Real-time and historical level measurement records for bulk liquid chemical storage tanks in tank farms. Captures tank identifier, material stored, measurement timestamp, level in meters, volume in liters or cubic meters, mass in kg, temperature at measurement, density, ullage (available headspace), high-level alarm status, low-level alarm status, and data source (Aveva PI System historian tag). Supports continuous inventory tracking for bulk chemicals without discrete lot tracking.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`inventory_adjustment` (
    `inventory_adjustment_id` BIGINT COMMENT 'Unique surrogate identifier for each inventory adjustment record in the Chemical Mfg lakehouse silver layer. Primary key for this entity.',
    `batch_record_id` BIGINT COMMENT 'Foreign key linking to production.batch_record. Business justification: Inventory adjustments in chemical manufacturing are frequently triggered by batch yield variances or quality rejections. Linking to batch_record enables direct adjustment-to-batch traceability for var',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Adjustments affect financial valuation per product; linking to chemical_product enables audit trails, cost allocation, and regulatory impact analysis.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Links adjustments to cost centers for variance analysis and internal cost control reporting.',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to maintenance.equipment. Business justification: Adjustments caused by equipment failures or repairs; needed for audit trail linking inventory adjustments to affected equipment.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Period-end close controls: inventory adjustments must be posted in the correct fiscal period. Linking to fiscal_period enables automated period validation, prevents backdating violations, and supports',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Ensures each inventory adjustment posts to the appropriate GL account for financial statements and audit trails.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: SOX compliance and financial audit trail: every inventory adjustment (write-off, revaluation, shrinkage) generates a journal entry in chemical manufacturing. Linking enables direct traceability from i',
    `lot_id` BIGINT COMMENT 'Reference to the specific production or procurement lot (batch) whose stock is being adjusted. Critical for FIFO/FEFO lot rotation compliance and traceability in chemical manufacturing.',
    `material_master_id` BIGINT COMMENT 'Reference to the material (raw material, intermediate, finished good, or packaging material) whose stock quantity is being adjusted. Corresponds to the SAP MM material master record.',
    `mrp_run_id` BIGINT COMMENT 'Foreign key linking to planning.mrp_run. Business justification: Inventory adjustments (write-offs of expired chemicals, spill losses, correction postings) change available stock and trigger MRP re-runs to recalculate net requirements. Linking adjustment to the sub',
    `original_adjustment_inventory_adjustment_id` BIGINT COMMENT 'Self-referencing identifier pointing to the original inventory adjustment record that this record reverses. Populated only when reversal_flag is True. Enables full reversal chain traceability for audit and SOX compliance.',
    `quality_deviation_id` BIGINT COMMENT 'Foreign key linking to quality.quality_deviation. Business justification: Inventory adjustments for quality-related scrap, rework, or write-offs must reference the triggering quality deviation. This FK enables cost-of-quality reporting, regulatory traceability for material ',
    `safety_incident_id` BIGINT COMMENT 'Foreign key linking to ehs.safety_incident. Business justification: Inventory write-offs due to spills, fires, or contamination must reference the triggering safety incident for SOX compliance, insurance claims, and EHS cost tracking. The plain-text ehs_incident_refer',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: An inventory adjustment corrects a specific stock positions quantity. Adding stock_position_id FK to inventory.stock_position creates a direct link between adjustment records and the affected positio',
    `usage_decision_id` BIGINT COMMENT 'Foreign key linking to quality.usage_decision. Business justification: Inventory adjustments triggered by QM usage decisions (scrapping rejected lots, releasing blocked stock) must reference the authorizing usage decision. This is a standard QM-MM integration point in ch',
    `warehouse_location_id` BIGINT COMMENT 'Reference to the warehouse storage location, tank farm, or bin where the adjusted stock resides. Integrates with SAP EWM for warehouse operations and hazardous material storage compliance.',
    `adjustment_status` STRING COMMENT 'Current lifecycle state of the inventory adjustment record, tracking progression from initial draft through dual-authorization approval (required for SOX-controlled threshold adjustments) to final posting or reversal in SAP MM.. Valid values are `draft|pending_approval|approved|posted|reversed|rejected`',
    `adjustment_timestamp` TIMESTAMP COMMENT 'The principal real-world business event timestamp recording when the inventory adjustment was physically executed or the stock correction was applied. Distinct from the record creation audit timestamp. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `adjustment_type` STRING COMMENT 'Classification of the inventory adjustment indicating the business reason category: write-off (stock reduction for loss/destruction), write-up (stock increase for found goods), count_variance (physical inventory count discrepancy posting), damage (goods damaged in storage or handling), obsolescence (expired or out-of-spec material), or revaluation (value correction). [ENUM-REF-CANDIDATE: write_off|write_up|count_variance|damage|obsolescence|revaluation|transfer_correction|system_correction — promote to reference product]. Valid values are `write_off|write_up|count_variance|damage|obsolescence|revaluation`',
    `approval_date` DATE COMMENT 'The calendar date on which the inventory adjustment received its final required authorization. Used for SOX compliance reporting and aging analysis of pending adjustments. Format: yyyy-MM-dd.',
    `capa_reference` STRING COMMENT 'Reference number linking this inventory adjustment to an associated CAPA (Corrective and Preventive Action) record when the adjustment triggers or is part of a quality or process improvement action. Supports ISO 9001 quality management traceability.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this inventory adjustment record was first created in the system. Used for data lineage, SOX audit trails, and lakehouse ingestion tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the financial impact value is expressed (e.g., USD, EUR, GBP). Supports multi-currency financial reporting and consolidation.. Valid values are `^[A-Z]{3}$`',
    `document_number` STRING COMMENT 'Externally-known business identifier for the inventory adjustment document, typically matching the SAP MM material document number generated at the time of posting. Used for cross-referencing with ERP and audit trails.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `financial_impact_value` DECIMAL(18,2) COMMENT 'The monetary value impact of the inventory adjustment on the balance sheet, calculated as adjustment quantity multiplied by the standard or moving average price of the material. Positive for write-ups, negative for write-offs. Used for COGS (Cost of Goods Sold) reporting and SOX financial controls.',
    `hazardous_material_flag` BOOLEAN COMMENT 'Boolean flag indicating whether the material being adjusted is classified as hazardous under GHS, OSHA, or DOT regulations. When True, additional EHS (Environment Health and Safety) reporting and disposal compliance requirements apply to the adjustment.',
    `material_description` STRING COMMENT 'Human-readable description of the material being adjusted, as maintained in the SAP MM material master. Supports reporting and analytics without requiring a join to the material master table.',
    `material_number` STRING COMMENT 'SAP MM material number (alphanumeric code) identifying the specific chemical, raw material, intermediate, or finished good subject to the inventory adjustment. Enables direct cross-reference to SAP S/4HANA without relying solely on the surrogate key.. Valid values are `^[A-Z0-9-]{1,18}$`',
    `movement_type_code` STRING COMMENT 'SAP MM movement type code that classifies the goods movement transaction (e.g., 551 for scrapping, 701 for physical inventory difference posting). Determines the accounting entries and stock update logic in SAP.. Valid values are `^[0-9]{3}$`',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, instructions, or context provided by the requestor or approver regarding the inventory adjustment. Supports operational communication and audit documentation.',
    `physical_inventory_document` STRING COMMENT 'SAP MM physical inventory document number associated with this adjustment when the adjustment originates from a physical inventory count (cycle count or annual count). Null for non-count-related adjustments such as damage write-offs.. Valid values are `^[0-9]{10}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing site or distribution center where the inventory adjustment is being made. Supports multi-site inventory management and plant-level financial reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `posting_date` DATE COMMENT 'The accounting posting date on which the inventory adjustment is recorded in the general ledger and stock accounts in SAP FI/CO. May differ from the adjustment timestamp if adjustments are posted retroactively within an open period. Format: yyyy-MM-dd.',
    `quantity` DECIMAL(18,2) COMMENT 'The quantity of material being adjusted, expressed as a positive value for stock increases (write-ups, found goods) or negative value for stock reductions (write-offs, damage, count shortages). Stored in the base unit of measure of the material.',
    `quarantine_flag` BOOLEAN COMMENT 'Boolean flag indicating whether the material lot being adjusted was in quarantine status (OOS – Out of Specification or OOT – Out of Trend hold) at the time of the adjustment. Supports QM (Quality Management) traceability and regulatory compliance.',
    `reason_code` STRING COMMENT 'Standardized reason code classifying the root cause or business justification for the inventory adjustment (e.g., PHYS_INV_DIFF for physical inventory difference, DAMAGE_STORAGE for storage damage, EXPIRY for expired material). Drives financial posting rules and regulatory reporting.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `reason_description` STRING COMMENT 'Free-text narrative description providing additional context for the inventory adjustment beyond the standardized reason code. Captures specific circumstances such as spill details, damage cause, or discrepancy explanation for audit and CAPA purposes.',
    `reversal_flag` BOOLEAN COMMENT 'Boolean flag indicating whether this inventory adjustment record is a reversal of a previously posted adjustment. True = this record reverses a prior adjustment; False = original adjustment. Supports audit trail integrity and double-entry accounting reconciliation.',
    `sap_material_document_number` STRING COMMENT 'The SAP MM material document number generated when the inventory adjustment is posted in SAP S/4HANA. Serves as the primary cross-reference between the lakehouse silver layer record and the ERP system of record for reconciliation and audit purposes.. Valid values are `^[0-9]{10}$`',
    `sap_material_document_year` STRING COMMENT 'The fiscal year associated with the SAP MM material document number. Required because SAP material document numbers are unique only within a fiscal year; combined with sap_material_document_number provides a globally unique ERP reference.',
    `sox_threshold_exceeded` BOOLEAN COMMENT 'Boolean flag indicating whether the financial impact value of this adjustment exceeds the SOX dual-authorization threshold, triggering the requirement for a secondary approver. True = dual authorization required and applied; False = single authorization sufficient.',
    `sox_threshold_value` DECIMAL(18,2) COMMENT 'The monetary threshold value above which a second approver is required per SOX internal control policy. Stored on the record for audit traceability as thresholds may be updated over time.',
    `storage_location_code` STRING COMMENT 'SAP storage location code (e.g., warehouse zone, tank farm area, quarantine area) within the plant where the adjusted material is stored. Supports hazardous material segregation compliance and EWM warehouse operations.. Valid values are `^[A-Z0-9]{1,10}$`',
    `unit_of_measure` STRING COMMENT 'The unit of measure in which the adjustment quantity is expressed (e.g., KG for kilograms, L for liters, MT for metric tons, DRUM for drum containers). Aligns with SAP MM base unit of measure for the material. [ENUM-REF-CANDIDATE: KG|LB|L|GAL|MT|EA|BAG|DRUM|IBC|TON — 10 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this inventory adjustment record was last modified, supporting change tracking and SOX dual-authorization audit requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `valuation_price` DECIMAL(18,2) COMMENT 'The unit price (standard cost or moving average price) used to calculate the financial impact value of the adjustment at the time of posting. Captured for audit traceability as prices may change over time.',
    CONSTRAINT pk_inventory_adjustment PRIMARY KEY(`inventory_adjustment_id`)
) COMMENT 'Record of inventory adjustments made to correct stock quantities outside of normal goods movement transactions, including write-offs, write-ups, count variance postings, and damage adjustments. Captures adjustment document number, material, lot, location, adjustment quantity (positive or negative), adjustment reason code, approver, approval date, financial impact value, and SAP MM material document reference. Requires dual authorization for adjustments above threshold values per SOX controls.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`consignment_stock` (
    `consignment_stock_id` BIGINT COMMENT 'Unique surrogate identifier for each consignment stock record in the Chemical Mfg inventory system. Primary key for the consignment_stock data product.',
    `billing_schedule_id` BIGINT COMMENT 'Foreign key linking to billing.billing_schedule. Business justification: Consignment stock arrangements in chemical manufacturing are governed by billing schedules defining when consumption triggers invoicing. Linking consignment_stock to billing_schedule enables automated',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Consignment reporting and liability transfer depend on knowing the exact chemical product, supporting inventory valuation and compliance checks.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to supply.contract. Business justification: Consignment stock arrangements in chemical manufacturing are governed by supply contracts defining holding limits, settlement terms, and liability transfer. Linking consignment_stock to the governing ',
    `customer_allocation_id` BIGINT COMMENT 'Foreign key linking to planning.customer_allocation. Business justification: Consignment stock at customer sites in chemical manufacturing is governed by customer allocation agreements that define quantity entitlements. The consignment stock record must reference the customer ',
    `distributor_agreement_id` BIGINT COMMENT 'Foreign key linking to sales.distributor_agreement. Business justification: Consignment inventory management: chemical manufacturers place product at distributor locations under a specific distributor agreement governing ownership transfer, settlement terms, and liability. Th',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to supply.goods_receipt. Business justification: Consignment stock receipts are documented via goods receipts in chemical manufacturing. Linking consignment_stock to goods_receipt enables settlement reconciliation and CoA verification; goods_receipt',
    `invoice_id` BIGINT COMMENT 'Foreign key linking to billing.invoice. Business justification: Consignment stock consumption in chemical manufacturing generates settlement invoices. consignment_stock.settlement_document_number is a denormalized invoice reference. Replacing it with a proper invo',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: Consignment stock is tracked at the lot level — vendor-owned stock held at the manufacturers premises is identified by lot/batch. The lot_number STRING column is denormalized; adding lot_id FK to inv',
    `manufacturing_order_id` BIGINT COMMENT 'Foreign key linking to production.manufacturing_order. Business justification: Consignment stock consumed in chemical production must be linked to the manufacturing order that consumed it for liability transfer and settlement processing. Required for consignment settlement billi',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the chemical raw material, intermediate, or packaging material held on consignment. Corresponds to SAP MM material master.',
    `price_agreement_id` BIGINT COMMENT 'Foreign key linking to sales.price_agreement. Business justification: Consignment settlement pricing: consignment stock consumed by a distributor is invoiced under a specific price agreement. Chemical manufacturers require this link for automated consignment settlement ',
    `quality_specification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_specification. Business justification: Consignment stock at customer sites must be managed against the agreed quality specification. coa_reference on consignment_stock is a plain text field. FK to quality_specification enables spec complia',
    `sds_record_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.sds_record. Business justification: Consignment stock of hazardous chemicals held at customer sites requires a current SDS for OSHA HazCom, REACH, and local regulatory compliance. Chemical manufacturers must ensure the SDS version accom',
    `site_id` BIGINT COMMENT 'Foreign key linking to customer.site. Business justification: Needed for Consignment Stock Management to record the customer site where consigned inventory is stored, supporting inventory visibility and billing.',
    `standard_cost_id` BIGINT COMMENT 'Foreign key linking to finance.standard_cost. Business justification: Consignment stock valuation and liability recognition: consignment_value must be computed from standard cost for balance sheet and consignment settlement reporting. Chemical manufacturers must value c',
    `storage_bin_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_bin. Business justification: consignment_stock has a storage_bin STRING column representing the bin where vendor-owned stock is held. Adding storage_bin_id FK to inventory.storage_bin normalizes this reference and enables bin-lev',
    `vendor_id` BIGINT COMMENT 'Reference to the vendor (supplier) who legally owns the consignment stock until the agreed consumption trigger is met. Corresponds to the SAP MM vendor master record.',
    `warehouse_location_id` BIGINT COMMENT 'Reference to the warehouse storage location or tank farm bin where the consignment stock is physically held at the chemical manufacturers premises. Corresponds to SAP EWM storage location.',
    `aging_days` STRING COMMENT 'Number of calendar days the consignment stock has been held at the manufacturers premises since receipt date. Used for vendor-managed inventory (VMI) performance monitoring, slow-moving stock identification, and consignment agreement compliance (maximum holding period enforcement).',
    `coa_reference` STRING COMMENT 'Reference number of the vendor-provided Certificate of Analysis (COA) accompanying the consignment lot. Confirms the material meets agreed quality specifications. Linked to LabWare LIMS for incoming quality verification.',
    `consignment_quantity` DECIMAL(18,2) COMMENT 'Current quantity of vendor-owned consignment stock on hand at the manufacturers premises, expressed in the base unit of measure. Represents the unreceived (not yet financially owned) stock balance.',
    `consignment_stock_status` STRING COMMENT 'Current lifecycle status of the consignment stock record. active = vendor-owned stock available for consumption; consumed = fully consumed and liability transferred; partially_consumed = partially drawn down; returned = returned to vendor; expired = past expiration date; quarantine = held pending quality disposition.. Valid values are `active|consumed|partially_consumed|returned|expired|quarantine`',
    `consignment_value` DECIMAL(18,2) COMMENT 'Total financial value of the current consignment stock on hand, calculated as consignment_quantity multiplied by valuation_price. Used for balance sheet disclosure of vendor-owned stock, financial reporting, and off-balance-sheet liability tracking under FASB ASC 330 and SOX.',
    `consumed_quantity` DECIMAL(18,2) COMMENT 'Cumulative quantity of consignment stock that has been consumed (goods-issued to production or other cost centers) and for which financial liability has been transferred to the manufacturer. Used for settlement reconciliation and VMI performance reporting.',
    `consumption_trigger` STRING COMMENT 'The agreed business event that triggers financial liability transfer from vendor to manufacturer for consignment stock. Defines when ownership and payable obligation are created. Aligned with SAP MM consignment settlement process.. Valid values are `goods_issue|production_order_confirmation|invoice_verification|periodic_settlement|manual_withdrawal`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the consignment stock record was first created in the system, typically upon goods receipt posting in SAP MM. Used for audit trail, data lineage, and SOX financial reporting compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the valuation price (e.g., USD, EUR, GBP). Required for multi-currency financial reporting and foreign exchange revaluation under FASB and SOX.. Valid values are `^[A-Z]{3}$`',
    `expiration_date` DATE COMMENT 'Date after which the consignment material is no longer suitable for use per quality specifications or regulatory requirements. Drives FEFO lot rotation, quarantine triggers, and vendor return decisions. Critical for GMP and chemical stability compliance.',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the consignment stock material is classified as hazardous under GHS, DOT, or OSHA regulations. Drives storage compliance requirements, SDS documentation obligations, and EHS reporting under TSCA and REACH.',
    `last_consumption_date` DATE COMMENT 'Date of the most recent goods issue (consumption) from this consignment stock lot. Used for slow-moving stock analysis, VMI replenishment planning, and consignment agreement compliance monitoring.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the consignment stock record (e.g., quantity adjustment, status change, quarantine flag update). Supports data lineage, change audit, and Silver layer delta processing in the Databricks Lakehouse.',
    `liability_transfer_date` DATE COMMENT 'Date on which financial ownership and payable liability for the consignment stock transferred from the vendor to the manufacturer, triggered by the agreed consumption event. Used for accounts payable accrual and financial period-end reporting under SOX and FASB ASC 330.',
    `maximum_holding_days` STRING COMMENT 'Maximum number of days the consignment stock may be held at the manufacturers premises per the consignment agreement before automatic return or forced consumption. Breach of this threshold may trigger penalty clauses or mandatory settlement.',
    `maximum_stock_level` DECIMAL(18,2) COMMENT 'Maximum quantity of consignment stock permitted at the manufacturers premises per the VMI or consignment agreement. Prevents over-stocking of hazardous chemicals and ensures compliance with site storage limits under OSHA PSM and EPA RMP.',
    `minimum_stock_level` DECIMAL(18,2) COMMENT 'Minimum quantity of consignment stock that must be maintained at the manufacturers premises per the VMI agreement to ensure uninterrupted production supply. Triggers vendor replenishment when consignment_quantity falls below this threshold.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing site or facility where the consignment stock is physically located. Used for plant-level inventory reporting and regulatory site compliance.',
    `purchase_order_number` STRING COMMENT 'SAP purchase order number associated with the consignment stock receipt. For consignment arrangements, this is typically a consignment PO (order type KE or KB in SAP MM) that governs the replenishment and settlement terms.',
    `quarantine_flag` BOOLEAN COMMENT 'Indicates whether the consignment stock lot is currently placed under quality quarantine and restricted from consumption pending laboratory testing or quality disposition. Integrates with LabWare LIMS quality hold status and SAP QM usage decision.',
    `quarantine_reason` STRING COMMENT 'Reason code for placing the consignment stock under quarantine. OOS (Out of Specification), OOT (Out of Trend), vendor deviation, physical damage, contamination suspicion, pending COA (Certificate of Analysis), or regulatory hold. Supports CAPA initiation and quality investigation. [ENUM-REF-CANDIDATE: oos_result|oot_result|vendor_deviation|damaged|contamination_suspect|pending_coa|regulatory_hold — 7 candidates stripped; promote to reference product]',
    `receipt_date` DATE COMMENT 'Date on which the vendor-owned consignment stock was physically received and placed at the manufacturers premises. Used for aging calculation, FIFO/FEFO rotation, and consignment agreement compliance tracking.',
    `retest_date` DATE COMMENT 'Date by which the consignment lot must be retested by the quality laboratory to confirm continued conformance to specification before use. Common for chemical raw materials with defined shelf-life stability windows. Sourced from LabWare LIMS batch records.',
    `returned_quantity` DECIMAL(18,2) COMMENT 'Quantity of consignment stock returned to the vendor without consumption, typically due to quality rejection, expiration, or excess inventory. Recorded as a consignment return movement in SAP MM.',
    `storage_temperature_max_c` DECIMAL(18,2) COMMENT 'Maximum permitted storage temperature in degrees Celsius for the consignment material as specified in the SDS or vendor COA. Critical for flammable, reactive, or thermally unstable chemical feedstocks.',
    `storage_temperature_min_c` DECIMAL(18,2) COMMENT 'Minimum required storage temperature in degrees Celsius for the consignment material as specified in the SDS or vendor COA. Ensures compliant storage conditions for temperature-sensitive chemicals and prevents degradation or hazardous reactions.',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the consignment quantity (e.g., KG for kilograms, L for litres, MT for metric tonnes, DRUM for drum containers). Aligned with SAP MM base UOM and chemical industry standard packaging units. [ENUM-REF-CANDIDATE: KG|LB|L|GAL|MT|TON|M3|BAG|DRUM|IBC — 10 candidates stripped; promote to reference product]',
    `valuation_price` DECIMAL(18,2) COMMENT 'Agreed unit price at which the consignment stock will be valued upon consumption and liability transfer. Used for inventory valuation, COGS calculation, and accounts payable settlement. Sourced from SAP MM purchasing info record or consignment agreement.',
    CONSTRAINT pk_consignment_stock PRIMARY KEY(`consignment_stock_id`)
) COMMENT 'Record tracking vendor-owned consignment stock held at the chemical manufacturers premises but not yet financially owned. Captures consignment agreement reference, vendor, material, lot, quantity on consignment, storage location, receipt date, agreed consumption trigger, valuation price, liability transfer date, and aging days. Enables accurate financial reporting by distinguishing owned stock from consignment stock in SAP MM special stock management. Supports vendor-managed inventory (VMI) arrangements common in chemical feedstock supply.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`interplant_transfer` (
    `interplant_transfer_id` BIGINT COMMENT 'Primary key for interplant_transfer',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Transfer orders must reference the chemical product to calculate hazard handling, track REACH status, and generate correct shipping documentation.',
    `inspection_lot_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_lot. Business justification: Interplant transfers of chemicals require QM inspection lots at the receiving plant (goods receipt inspection). In chemical manufacturing, transferred materials must be re-inspected at the destination',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Project cost tracking for interplant movements: interplant transfers in chemical manufacturing are frequently funded by internal orders (plant turnarounds, capital projects). Linking enables cost trac',
    `invoice_id` BIGINT COMMENT 'Foreign key linking to billing.invoice. Business justification: Interplant transfers between legal entities in chemical manufacturing generate intercompany invoices for transfer pricing and cost allocation. Linking interplant_transfer to invoice enables intercompa',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: Inter‑plant transfer is tied to a specific lot; replace free‑text lot_number with FK for traceability.',
    `sds_record_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.sds_record. Business justification: DOT/ADR/IMDG hazmat transport regulations require SDS to accompany interplant transfers of hazardous chemicals. A direct FK from interplant_transfer to sds_record enables automated SDS attachment to s',
    `warehouse_location_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse_location. Business justification: Inter‑plant transfer originates from a warehouse location; replace string with FK.',
    `supply_plan_id` BIGINT COMMENT 'Foreign key linking to planning.supply_plan. Business justification: Interplant transfers in chemical manufacturing are planned supply movements between plants to balance inventory against regional demand. Transfers must reference the supply plan that authorized the mo',
    `transfer_order_id` BIGINT COMMENT 'Foreign key linking to inventory.transfer_order. Business justification: interplant_transfer has transfer_order_number (STRING) referencing the associated warehouse transfer order. transfer_order is in the inventory domain. Adding transfer_order_id FK normalizes this refer',
    `actual_goods_issue_date` DATE COMMENT 'Actual date on which the goods issue posting was made in SAP MM, confirming physical departure of material from the sending plant. Used for transit time analysis and on-time shipment KPI reporting.',
    `actual_goods_receipt_date` DATE COMMENT 'Actual date on which the goods receipt posting was made in SAP MM at the receiving plant, confirming physical arrival and acceptance of the transferred material. Used for transit time calculation and inventory reconciliation.',
    `bill_of_lading_number` STRING COMMENT 'Official bill of lading document number issued for the shipment. Serves as the legal contract of carriage and is required for hazardous material transport documentation under DOT regulations and customs compliance.',
    `carrier_name` STRING COMMENT 'Name of the logistics carrier or transport service provider responsible for moving the material between plants. Used for carrier performance tracking and freight cost allocation.',
    `carrier_reference_number` STRING COMMENT 'Carrier-assigned reference number (e.g., bill of lading number, waybill number, or pro number) for the shipment. Used to cross-reference with Oracle Transportation Management and carrier tracking systems.',
    `created_by_user` STRING COMMENT 'SAP user ID of the person who created the stock transfer order in SAP S/4HANA. Required for audit trail, authorization control, and SOX compliance documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the stock transfer order was first created in the source system (SAP S/4HANA). Represents the business event of order initiation, not the ETL load time.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the transfer value (e.g., USD, EUR). Required for multi-currency inter-company transfer valuation and financial reporting under FASB and SOX.. Valid values are `^[A-Z]{3}$`',
    `delivery_document_number` STRING COMMENT 'SAP outbound delivery document number created in SAP EWM/SD for the physical shipment execution of this stock transfer order. Links the STO to the warehouse execution and shipping documents.',
    `expiration_date` DATE COMMENT 'Shelf-life expiration date of the transferred lot. Governs FEFO (First Expired First Out) inventory rotation logic and ensures expired or near-expiry materials are flagged before transfer. Mandatory for regulated chemicals and pharmaceutical-grade materials.',
    `hazmat_indicator` BOOLEAN COMMENT 'Flag indicating whether the transferred material is classified as a hazardous material requiring special handling, labeling, and transport documentation under DOT, GHS, and IMDG regulations. Triggers mandatory SDS/MSDS documentation and emergency response procedures.',
    `intransit_quantity` DECIMAL(18,2) COMMENT 'Quantity of material currently in transit between the sending and receiving plants — goods issued but not yet goods-receipted. Represents the stock-in-transit position used for real-time inventory visibility and financial valuation of in-transit inventory.',
    `issued_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of material physically issued (goods issued) from the sending plants inventory at the time of transfer. May differ from transfer_quantity due to partial shipments or measurement variances.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the stock transfer order record in the source system. Used for change tracking, audit trails, and incremental data pipeline processing.',
    `material_description` STRING COMMENT 'Short descriptive name of the material being transferred as maintained in the SAP material master. Provides human-readable identification for operational and compliance reporting.',
    `material_number` STRING COMMENT 'SAP material master number uniquely identifying the chemical, raw material, intermediate, finished good, or packaging material being transferred. Serves as the primary material reference across SAP MM, PP, and QM modules.',
    `planned_goods_issue_date` DATE COMMENT 'Planned date on which goods are scheduled to be issued from the sending plants inventory. Derived from the requested delivery date and transit lead time in SAP MM planning.',
    `priority` STRING COMMENT 'Business priority level assigned to the stock transfer order, used to sequence fulfillment and logistics scheduling. Urgent transfers may be triggered by production line stoppages or critical inventory shortfalls.. Valid values are `urgent|high|normal|low`',
    `purchase_order_number` STRING COMMENT 'SAP purchase order number associated with this stock transfer order for cross-company or third-party warehouse transfers. Links the STO to the procurement document for financial settlement and accounts payable processing.',
    `quarantine_status` STRING COMMENT 'Quality management status of the transferred material lot indicating whether it is available for unrestricted use or held under quarantine/quality hold pending inspection or testing. Integrates with SAP QM and LabWare LIMS quality disposition workflows.. Valid values are `unrestricted|quarantined|quality_hold|released|rejected`',
    `received_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of material confirmed as received (goods received) at the destination plant. Used to calculate transfer variances, identify transit losses, and trigger inventory reconciliation. Populated upon goods receipt posting in SAP MM.',
    `receiving_plant_code` STRING COMMENT 'SAP plant code identifying the destination plant, distribution center, or external warehouse that will receive the transferred material. Corresponds to the receiving plant in SAP MM stock transfer processing.',
    `receiving_plant_name` STRING COMMENT 'Descriptive name of the destination plant or facility receiving the stock transfer. Provides human-readable context for reporting and operational dashboards without requiring a join to the plant master.',
    `receiving_storage_location` STRING COMMENT 'SAP storage location code within the receiving plant where the material will be placed upon arrival. Identifies the target warehouse area, tank farm, or storage bin at the destination facility.',
    `requested_delivery_date` DATE COMMENT 'Date by which the transferred material is required to arrive at the receiving plant. Used for production planning, supply chain scheduling, and on-time delivery performance measurement.',
    `sap_movement_type` STRING COMMENT 'SAP MM movement type code governing the inventory and accounting postings for this transfer (e.g., 641 for goods issue for STO, 101 for goods receipt). Determines the financial and inventory impact in SAP S/4HANA.',
    `sending_plant_code` STRING COMMENT 'SAP plant code identifying the originating plant or manufacturing facility from which the material is being transferred. Corresponds to the issuing plant in SAP MM stock transfer processing.',
    `sending_plant_name` STRING COMMENT 'Descriptive name of the originating plant or facility issuing the stock transfer. Provides human-readable context for reporting and operational dashboards without requiring a join to the plant master.',
    `special_stock_indicator` STRING COMMENT 'SAP special stock type indicator identifying whether the transferred material is standard unrestricted stock or a special stock category such as consignment, project stock, or sales order stock. Affects inventory valuation and availability checking.. Valid values are `unrestricted|consignment|project_stock|sales_order_stock|returnable_packaging`',
    `transfer_quantity` DECIMAL(18,2) COMMENT 'Ordered quantity of material to be transferred from the sending plant to the receiving plant, expressed in the base unit of measure. Represents the planned transfer amount at order creation.',
    `transfer_reason` STRING COMMENT 'Business reason or justification for initiating the inter-plant stock transfer (e.g., production replenishment, inventory rebalancing, quality rework, customer order fulfillment). Used for operational analytics and cost allocation.',
    `transfer_status` STRING COMMENT 'Current lifecycle status of the inter-plant stock transfer order. Tracks progression from creation through in-transit movement to receipt confirmation at the destination plant. [ENUM-REF-CANDIDATE: created|in_transit|partially_received|received|confirmed|cancelled — promote to reference product if additional statuses are required]. Valid values are `created|in_transit|partially_received|received|confirmed|cancelled`',
    `transfer_type` STRING COMMENT 'Classification of the inter-plant transfer indicating the nature of the movement (e.g., plant-to-plant, plant-to-distribution center, cross-company transfer). Determines the SAP movement type and accounting treatment in FI/CO.. Valid values are `plant_to_plant|plant_to_dc|dc_to_plant|plant_to_external_wh|cross_company`',
    `transfer_value` DECIMAL(18,2) COMMENT 'Monetary value of the transferred material quantity based on the standard or moving average price at the sending plant. Used for inter-company or inter-plant inventory valuation and financial settlement in SAP FI/CO. Expressed in the company currency.',
    `transport_mode` STRING COMMENT 'Mode of transportation used to move the material between plants (e.g., road tanker, rail car, pipeline, barge). Relevant for hazardous material transport compliance under DOT 49 CFR and IATA/IMDG regulations for chemical shipments.. Valid values are `road|rail|pipeline|barge|air|intermodal`',
    `un_number` STRING COMMENT 'UN four-digit identification number assigned to hazardous materials for transport classification (e.g., UN1993 for flammable liquids). Required on shipping documents and placards for hazardous chemical transport under DOT 49 CFR and IMDG regulations.. Valid values are `^UN[0-9]{4}$`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the transfer quantity (e.g., KG for kilograms, L for liters, MT for metric tons, DRUM for drum containers). Aligns with SAP MM unit of measure configuration and chemical industry standard packaging units. [ENUM-REF-CANDIDATE: KG|LB|L|GAL|MT|EA|BAG|DRUM|IBC|TON — 10 candidates stripped; promote to reference product]',
    CONSTRAINT pk_interplant_transfer PRIMARY KEY(`interplant_transfer_id`)
) COMMENT 'Inter-plant or inter-warehouse stock transfer order record for moving materials between different plant locations, distribution centers, or external warehouses. Captures transfer order number, sending plant, receiving plant, material, lot, transfer quantity, unit of measure, requested delivery date, transport mode, carrier reference, in-transit quantity, and transfer status (created, in-transit, received, confirmed). Distinct from intra-warehouse transfer orders managed in SAP EWM.';

CREATE OR REPLACE TABLE `chemical_mfg_ecm`.`inventory`.`tank` (
    `tank_id` BIGINT COMMENT 'Primary key for tank',
    `chemical_product_id` BIGINT COMMENT 'Foreign key linking to product.chemical_product. Business justification: Each storage tank in chemical manufacturing is dedicated to a specific chemical product — this link enables hazmat compatibility validation, storage condition compliance checks (temperature, pressure ',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to maintenance.equipment. Business justification: In chemical manufacturing, every tank is a registered equipment asset in the CMMS for API 653 inspection scheduling, PSM compliance, and maintenance work order execution. A domain expert would immedia',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Fixed asset lifecycle management: storage tanks are capitalized fixed assets in chemical manufacturing. Linking enables depreciation tracking, insurance valuation, regulatory compliance (EPA/OSHA), an',
    `hazmat_storage_rule_id` BIGINT COMMENT 'Foreign key linking to inventory.hazmat_storage_rule. Business justification: tank has hazardous_class (STRING) indicating the hazmat classification of the stored chemical. Adding hazmat_storage_rule_id FK to inventory.hazmat_storage_rule links each tank to its governing storag',
    `manifolded_tank_id` BIGINT COMMENT 'Self-referencing FK on tank (manifolded_tank_id)',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to rawmaterial.material_master. Business justification: Tank farm management requires knowing which material_master record corresponds to the chemical stored in each tank for inspection scheduling, hazmat compliance, reorder triggering, and storage conditi',
    `operating_permit_id` BIGINT COMMENT 'Foreign key linking to ehs.operating_permit. Business justification: Individual tanks in chemical manufacturing are governed by specific air emission permits, storage permits, or Title V conditions. Linking each tank to its governing operating permit enables permit com',
    `warehouse_location_id` BIGINT COMMENT 'Identifier of the physical location or warehouse where the tank is installed.',
    `capacity_m3` DECIMAL(18,2) COMMENT 'Maximum volume the tank can hold, expressed in cubic metres.',
    `certification_expiry` DATE COMMENT 'Expiration date of the current certification.',
    `cleaning_frequency_days` STRING COMMENT 'Recommended interval between cleaning operations, in days.',
    `compliance_certification` STRING COMMENT 'Safety or environmental certification held by the tank.',
    `corrosion_rate_mm_per_year` DECIMAL(18,2) COMMENT 'Estimated material loss due to corrosion per year.',
    `current_volume_m3` DECIMAL(18,2) COMMENT 'Current amount of material stored in the tank, in cubic metres.',
    `expiration_date` DATE COMMENT 'Expiration date of the stored material, if applicable.',
    `fill_percentage` DECIMAL(18,2) COMMENT 'Current fill level expressed as a percentage of total capacity.',
    `gps_latitude` DOUBLE COMMENT 'Geographic latitude coordinate of the tank location.',
    `gps_longitude` DOUBLE COMMENT 'Geographic longitude coordinate of the tank location.',
    `hazardous_class` STRING COMMENT 'Hazard classification of the material according to regulatory standards.',
    `installation_date` DATE COMMENT 'Date the tank was installed and became operational.',
    `is_quarantined` BOOLEAN COMMENT 'Indicates whether the tank is under quarantine due to contamination or safety concerns.',
    `last_cleaned_timestamp` TIMESTAMP COMMENT 'Date and time when the tank was last cleaned.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent safety or regulatory inspection.',
    `lot_number` STRING COMMENT 'Batch or lot identifier of the material currently stored.',
    `maintenance_status` STRING COMMENT 'Current maintenance state of the tank.',
    `next_inspection_due` DATE COMMENT 'Scheduled date for the next required inspection.',
    `notes` STRING COMMENT 'Free‑form field for additional remarks or observations.',
    `owner_department` STRING COMMENT 'Business department responsible for the tank.',
    `pressure_psi` DECIMAL(18,2) COMMENT 'Real‑time internal pressure reading.',
    `pressure_rating_psi` DECIMAL(18,2) COMMENT 'Maximum allowable internal pressure, in pounds per square inch.',
    `quarantine_reason` STRING COMMENT 'Reason for placing the tank in quarantine.',
    `safety_valve_present` BOOLEAN COMMENT 'Indicates whether a safety relief valve is installed.',
    `safety_valve_type` STRING COMMENT 'Type of safety valve installed on the tank.',
    `tank_name` STRING COMMENT 'Human‑readable name or label assigned to the tank.',
    `tank_status` STRING COMMENT 'Current operational status of the tank.',
    `tank_type` STRING COMMENT 'Category of tank based on its functional purpose.',
    `temperature_c` DECIMAL(18,2) COMMENT 'Real‑time temperature reading inside the tank.',
    `temperature_rating_c` DECIMAL(18,2) COMMENT 'Maximum allowable operating temperature, in degrees Celsius.',
    CONSTRAINT pk_tank PRIMARY KEY(`tank_id`)
) COMMENT 'Master reference table for tank. Referenced by tank_id.';

